INSERT INTO public."Config_Empresas" ("id_empresa", "nomempresa", "es_principal", "modo_sitio", "db_engine", "habilitado", "modo", "telefonowhatsapp", "correoempresarial", "foto_agente", "slogan", "mensaje1", "mensaje2", "mision", "vision", "valores", "impacto", "politicas", "ubicacion_url", "ubicacion", "direccion", "logo_url", "fecha_creacion", "tipo_negocio", "color_tema", "formulario", "modo_creditos", "creditos_totales", "fecha_vencimiento", "origen_politicas", "infobanco", "infocuenta", "infonom", "enlace_oficial", "alias_seo", "rsface", "rsinsta", "rstik", "usa_otp_entrega", "usa_features_estandar", "is_isolated", "usa_soporte_ia", "id_notebooklm", "usa_qr_sitio", "usa_reservaciones", "id_calendario_google", "drive_folder_id", "costo_envio", "descripcion", "factura", "autodepuracion", "whatsapp_negocio", "url_logo_identidad", "giro_especifico", "slogan_empresa", "agent_enabled") VALUES ('EVASOL', 'Evasol', FALSE, 'HYBRID', 'GSHEETS', TRUE, 'PROD', 528112710091, 'sirisenergiasolar@grupoevasol.com', 'https://drive.google.com/file/d/1URf9kXtovqqCVg8obQSqXzUm3MQkMjZ2/view?usp=sharing', 'Energía para tu vida', 'Bienvenido', 'Esperamos tus consultas.', 'Iluminar y potenciar el camino de organizaciones y profesionales con soluciones jurídicas y corporativas estratégicas e innovadoras, que aseguren su crecimiento sostenible, cumplimiento normativo y una gestión eficiente en un entorno empresarial dinámico y complejo.', 'Ser el referente líder en asesoría jurídica y consultoría corporativa, reconocido por nuestra capacidad de anticipación, la excelencia en la implementación de estrategias y la creación de un valor duradero, contribuyendo a la formación de un ecosistema empresarial ético, innovador y próspero en la región.', 'Integridad y Transparencia: Actuamos con honestidad inquebrantable, ética profesional y total transparencia en todas nuestras operaciones y comunicaciones. La confianza es nuestro activo más valioso. Innovación Estratégica: Buscamos constantemente soluciones creativas y vanguardistas, anticipando desafíos y transformando obstáculos en oportunidades de crecimiento. No solo resolvemos problemas, los prevenimos y creamos futuro. Excelencia y Precisión: Nos comprometemos con la calidad superior en cada servicio que ofrecemos, prestando atención al detalle y persiguiendo la perfección en la ejecución para superar las expectativas de nuestros clientes. Orientación al Cliente y Colaboración: Ponemos las necesidades y objetivos de nuestros clientes en el centro de nuestra estrategia, construyendo relaciones de confianza mutua y colaboración que nos permiten ser verdaderos socios en su éxito. Claridad y Soluciones Prácticas: Transformamos la complejidad del entorno jurídico y corporativo en respuestas claras, concisas y acciones prácticas. Nuestra finalidad es simplificar para empoderar.', 'Fortalecimiento Empresarial Sostenible: Impulsamos la resiliencia, la competitividad y el crecimiento a largo plazo de nuestros clientes, dotándolos de las herramientas y estrategias necesarias para navegar con éxito en un mercado cambiante. Fomento de una Cultura de Cumplimiento y Ética: Contribuimos a la creación de entornos empresariales íntegros, responsables y transparentes, donde el cumplimiento normativo es visto como una ventaja competitiva y un pilar de la reputación. Impulso de la Innovación Responsable: Asesoramos y promovemos prácticas que equilibran el progreso tecnológico y empresarial con la responsabilidad social, ambiental y el bienestar colectivo. Desarrollo Profesional y Conocimiento: Invertimos en el crecimiento y la especialización de nuestro equipo y contribuimos a la formación del sector, compartiendo conocimiento y promoviendo las mejores prácticas jurídicas y corporativas. Acceso a la Justicia y Asesoramiento Transparente: Democratizamos el acceso a un asesoramiento jurídico y corporativo de alta calidad, desmitificando procesos y facilitando la toma de decisiones informadas para un espectro más amplio de organizaciones.', 'En Evasol, nuestra razón de ser es iluminar el camino hacia soluciones estratégicas para nuestros clientes. Estos documentos son la manifestación de nuestra Misión, Visión, Valores e Impacto, y guían cada interacción, decisión y proceso dentro de nuestra organización. Reflejan nuestro compromiso con la excelencia, la integridad y la innovación, asegurando que cada servicio que ofrecemos no solo cumpla, sino que supere las expectativas. I. Políticas del Negocio de Evasol: Estas políticas establecen los principios rectores que definen la cultura, la ética y las operaciones de Evasol. 1. Política de Ética y Conducta Profesional: Integridad Inquebrantable: Todos los colaboradores de Evasol se comprometen a actuar con la máxima honestidad, transparencia y rectitud en todas sus actividades, tanto internas como externas. Confidencialidad Absoluta: La información de nuestros clientes, socios y de Evasol es tratada con la más estricta confidencialidad, tanto durante como después de la relación profesional. Se implementarán las medidas necesarias para proteger la privacidad y la seguridad de los datos. Imparcialidad y Objetividad: Ofrecemos asesoramiento imparcial y objetivo, basado en hechos, análisis riguroso y la mejor práctica profesional, siempre en el mejor interés de nuestros clientes. Respeto y No Discriminación: Promovemos un ambiente de trabajo y de interacción con clientes y terceros basado en el respeto mutuo, la diversidad y la inclusión, libre de cualquier forma de discriminación o acoso. 2. Política de Excelencia y Calidad en el Servicio: Estándares Superiores: Nos comprometemos a mantener los más altos estándares de calidad en todos los servicios, entregables y comunicaciones. Precisión y Rigor: Todo trabajo realizado por Evasol se caracteriza por su precisión, rigor jurídico y corporativo, y atención al detalle. Mejora Continua: Fomentamos una cultura de aprendizaje y mejora continua, invirtiendo en la formación y desarrollo profesional de nuestro equipo para mantenernos a la vanguardia de las mejores prácticas y regulaciones. 3. Política de Gestión de Conflictos de Interés: Identificación y Declaración: Todos los colaboradores están obligados a identificar y declarar cualquier situación, personal o profesional, que pueda generar un conflicto de interés real o aparente con los intereses de Evasol o de nuestros clientes. Resolución Transparente: En caso de un conflicto de interés, Evasol implementará procedimientos transparentes para su gestión, que pueden incluir la abstención, la asignación a otro equipo o la divulgación y consentimiento de las partes afectadas. 4. Política de Protección de Datos y Privacidad: Cumplimiento Normativo: Evasol se adhiere estrictamente a todas las leyes y regulaciones aplicables en materia de protección de datos personales (GDPR, LFPDPPP, etc.), asegurando su recolección, uso, almacenamiento y eliminación de forma lícita y segura. Seguridad de la Información: Implementamos medidas de seguridad técnicas y organizativas robustas para proteger la información confidencial y los datos personales contra accesos no autorizados, pérdida o alteración. 5. Política de Innovación Estratégica: Anticipación y Proactividad: Evasol invierte en investigación y análisis para anticipar tendencias y cambios en el entorno legal y corporativo, ofreciendo soluciones proactivas a nuestros clientes. Tecnología y Herramientas: Evaluamos e implementamos tecnologías y herramientas avanzadas que optimicen nuestros procesos, mejoren la eficiencia y la calidad de nuestros servicios. Creatividad y Soluciones a Medida: Fomentamos un enfoque creativo para el desarrollo de soluciones, adaptándonos a las necesidades específicas y únicas de cada cliente. 6. Política de Responsabilidad Social Corporativa (RSC): Contribución al Ecosistema Empresarial: Evasol se compromete a contribuir positivamente al desarrollo de un ecosistema empresarial ético, innovador y próspero, a través de nuestras prácticas y asesoramiento. Impacto Sostenible: Promovemos prácticas que generen un impacto sostenible en la sociedad y el medio ambiente, tanto en nuestra operación interna como en el asesoramiento a nuestros clientes.', 'CDMX, México', 'Av. Reforma 123', NULL, 'https://drive.google.com/file/d/144laQkO42SV-KdCGJqe41hOgmrwTHr96/view?usp=sharing', 45292, 'Energía Solar', '#2e7d32', TRUE, 'GLOBAL', 73, '01/31/2026', 'ROL', NULL, NULL, 'Armando Viñas', 'https://grupoevasol.com/?co=EVASOL#home', 'pollofritometroplex', '1A0hjIHPmzZgzfEsYhVwc-W9iUcIvcbcW', NULL, NULL, FALSE, TRUE, TRUE, TRUE, TRUE, TRUE, FALSE, NULL, NULL, NULL, NULL, TRUE, 90, NULL, NULL, 'Energía Solar', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Config_Empresas" ("id_empresa", "nomempresa", "es_principal", "modo_sitio", "db_engine", "habilitado", "modo", "telefonowhatsapp", "correoempresarial", "foto_agente", "slogan", "mensaje1", "mensaje2", "mision", "vision", "valores", "impacto", "politicas", "ubicacion_url", "ubicacion", "direccion", "logo_url", "fecha_creacion", "tipo_negocio", "color_tema", "formulario", "modo_creditos", "creditos_totales", "fecha_vencimiento", "origen_politicas", "infobanco", "infocuenta", "infonom", "enlace_oficial", "alias_seo", "rsface", "rsinsta", "rstik", "usa_otp_entrega", "usa_features_estandar", "is_isolated", "usa_soporte_ia", "id_notebooklm", "usa_qr_sitio", "usa_reservaciones", "id_calendario_google", "drive_folder_id", "costo_envio", "descripcion", "factura", "autodepuracion", "whatsapp_negocio", "url_logo_identidad", "giro_especifico", "slogan_empresa", "agent_enabled") VALUES ('PFM', 'Pollo Frito Metroplex', FALSE, 'NOHYBRID', 'SUPABASE', TRUE, 'PROD', 528110463721, 'rbtpdrn@gmail.com ', 'https://drive.google.com/uc?export=view&id=1vs8kAaRpIg9IWT75RiTidkp_KdzwzADJ', 'El mejor crunch!', 'hola muybuenos dias', '... Te esperamos proximante.!', 'Brindar a nuestros clientes comida deliciosa, fresca y hecha con cariño, ofreciendo el mejor sabor en pollo frito y complementos. Queremos que cada visita sea una experiencia agradable, rápida y accesible, donde todos se sientan como en casa.', 'Ser el lugar favorito de la comunidad para disfrutar buena comida con un servicio amable y familiar, creciendo paso a paso con esfuerzo, calidad y el cariño de nuestros clientes.', '1 Calidad, sabor y frescura. 2 Respeto y cercanía con nuestros clientes. 3 Trabajo en equipo y honestidad. 4 Pasión por servir y mejorar cada día.', 'Queremos generar sonrisas y buenos momentos, ofreciendo comida que une a familias y amigos. Contribuimos al bienestar de nuestra comunidad creando empleos locales y compartiendo el sabor de nuestra cocina con orgullo y corazón.', '**POLÍTICAS Y GARANTÍAS DE SERVICIO: POLLO METROPLEX** **1. COMPROMISO DE CALIDAD** Nuestra prioridad es el SABOR y la FRESCURA. Todos los alimentos, desde nuestras PZ DE POLLO ($19) hasta el PAQUETE FAMILIAR ($450), se preparan bajo estrictos estándares de higiene. Garantizamos que recibirás un producto CALIENTE y bien empaquetado. **2. LOGÍSTICA DE ENTREGA Y RECOLECCIÓN** Optimizamos tu tiempo y comodidad: * **ENTREGA A DOMICILIO:** Tarifa estándar de $30. Nos comprometemos a llevar tu pedido en el menor tiempo posible. * **PICK-UP (RECOGER):** Costo $0. Tu pedido estará listo y empacado a la hora acordada para agilizar tu día. **3. GARANTÍA DE SATISFACCIÓN Y DEVOLUCIONES** Tu inversión está segura con nosotros. * **RECLAMACIONES:** Deben realizarse dentro de los primeros 15 minutos tras recibir el pedido. * **ERRORES DE PEDIDO:** Si falta algún artículo (ej. Salsas, Tortillas) o el producto es incorrecto, realizaremos la REPOSICIÓN INMEDIATA o aplicaremos un crédito a tu favor para la próxima compra. * **CONDICIÓN:** Para validar cualquier garantía de calidad, es indispensable conservar el producto para su inspección o enviar evidencia fotográfica clara. No aceptamos devoluciones por gusto personal si el producto cumple con nuestros estándares. **4. PRECIOS Y PAGOS** Los precios mostrados en nuestro catálogo son FINALES. Nos reservamos el derecho de modificar tarifas, pero siempre respetaremos el precio acordado al momento de CERRAR EL TRATO. *** **DATOS DEL NEGOCIO** * **Nombre:** Pollo Metroplex * **Giro:** Alimentos y Bebidas (Pollo frito, Hamburguesas y Complementos) * **Canales de Venta:** Mostrador y Domicilio. * **Contacto Oficial:** [Insertar Teléfono/WhatsApp Oficial Aquí] *Para dudas administrativas no contempladas aquí, contacta directamente a nuestros CANALES OFICIALES.*', 'https://maps.app.goo.gl/YQaHWbm1SUScSJW46', 'Apodaca, N.L. Mex.', 'Av o primera # 101 Local B, Col. Metroplex entre la calle s 8 y s 10 Apodaca N.L.', 'https://drive.google.com/uc?export=view&id=1t6BmvpGTCR6-OZ3Nnx-yOmpohe5eCKvv', NULL, 'Alimentos', '#ff4500', FALSE, 'DIARIO', 100, '01/31/2026', NULL, 'Santander', '5579 1003 9373 7075 ', 'José Almaguer ', NULL, NULL, 'https://www.facebook.com/pollofrito.metroplex?mibextid=ZbWKwL', 'https://www.instagram.com/pollofrito_metroplex?igsh=bW83NHM5dHBuaGVx', 'https://www.tiktok.com/@pollofrito.metrop?_r=1&_t=ZS-92lhFax6xG8', TRUE, FALSE, FALSE, FALSE, NULL, NULL, NULL, NULL, NULL, 30, NULL, FALSE, 90, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
