INSERT INTO public."Config_Paginas" ("id_empresa", "id_pagina", "id_cluster", "meta_json", "schema_json", "contenido_json") VALUES ('ROBERTO_V', 'home', NULL, '{"title":"Inclusión Siglo 21 — Apoyo a Personas con Discapacidad","description":"Organización no lucrativa que apoya a personas con discapacidad visual, invidentes y adultos mayores en México.","keywords":["inclusión social","discapacidad visual","ONG México","apoyo adultos mayores"],"og_image":"","canonical_url":"https://grupoevasol.com/?co=ROBERTO_V#home"}', '{"@context":"https://schema.org","@type":"NGO","name":"Inclusión Siglo 21","description":"Asociación no lucrativa creada para apoyar a personas con discapacidad e invidentes.","url":"https://grupoevasol.com/?co=ROBERTO_V#home","telephone":"+525559755277","contactPoint":{"@type":"ContactPoint","telephone":"+525559755277","contactType":"customer support"}}', '{"H1":"Con Tu Donación, Juntos Hacemos Más","H3_1":"Somos Inclusión Siglo 21","p_intro":"Somos una Organización con la convicción de apoyar a nuestro prójimo con necesidades varias, discapacidad visual y adultos mayores.","p_problema":"Nuestra Misión:Cambiar la percepción hacia las personas con discapacidad, concentrándonos en las habilidades de cada uno e incluyéndolos en el ambiente social.","cta_texto":"Donar Ahora"}') ON CONFLICT DO NOTHING;
INSERT INTO public."Config_Paginas" ("id_empresa", "id_pagina", "id_cluster", "meta_json", "schema_json", "contenido_json") VALUES ('ROBERTO_V', 'museo', NULL, '{"title":"Museo Itinerante para Ciegos — Arte Táctil","description":"Museo adaptado para personas ciegas y débiles visuales en México. Arte y escultura que se puede tocar.","keywords":["museo itinerante","arte táctil","Diego Rivera tactil","museo accesible"],"og_image":"","canonical_url":"https://inclusionsiglo21.org/museo"}', '{"@context":"https://schema.org","@type":"Museum","name":"Museo Itinerante IS21","description":"Institución privada que exhibe obras de arte adaptadas táctilmente para ciegos.","url":"https://inclusionsiglo21.org/museo","audience":{"@type":"Audience","audienceType":"Personas con discapacidad visual"}}', '{"H1":"Museo Itinerante Inclusión Siglo 21","H2_1":"Arte que se Puede Tocar y Sentir","p_intro":"Como museo itinerante somos una institución al servicio de la sociedad que exhibe obras de arte en espacios ajenos.","H2_3":"Obras y Colecciones","p_pintores":"Obras adaptadas de Diego Rivera, Frida Kahlo y otros pintores famosos.","cta_texto":"Agendar Visita"}') ON CONFLICT DO NOTHING;
INSERT INTO public."Config_Paginas" ("id_empresa", "id_pagina", "id_cluster", "meta_json", "schema_json", "contenido_json") VALUES ('ConM40', 'home', NULL, '{"title":"Aumenta tu Pensión IMSS Ley 73 | Modalidad 40 Financiada","description":"Incremento de pensión hasta 300%. Financiamiento 100% de pago retroactivo Modalidad 40. No pagas nada hasta recibir tu pensión mejorada.","keywords":"IMSS, Modalidad 40, Pensión Ley 73, Retiro, Afore, Pago Retroactivo","robots":"index, follow"}', '{"@context":"https://schema.org","@type":"GovernmentService","name":"Asesoría Profesional en Pensiones IMSS","serviceType":"Financiamiento de Modalidad 40","offers":{"@type":"Offer","name":"Cero Inversión Inicial","description":"Financiamos tu retroactivo al 100% y pagas al recibir tu pensión."}}', '{"hero":{"h1":"<h1>¿Sabías que puedes incrementar tu pensión del IMSS hasta en un 300%?</h1>","h2":"<h2>Pensión Máxima para Ley 73: Nosotros financiamos tu futuro hoy</h2>","main_text":"<p>Si comenzaste a cotizar antes del 1 de julio de 1997, <strong>no te conformes con la pensión mínima</strong>. Gestionamos y financiamos al 100% tu pago retroactivo de la Modalidad 40.</p>","highlight_section":"<h3>Nuestro Compromiso: Cero Descapitalización</h3><p>El crédito y nuestros honorarios se pagan hasta que tu pensión mejorada sea una realidad.</p>","cta_banner":"<h3>¡Contáctanos y solicita tu cotización preliminar hoy mismo!</h3>","whatsapp_url":"https://wa.me/tu_numero?text=Hola! Quiero mi cotización preliminar para el incremento de mi pensión IMSS al 300%"},"footer_seo":{"h3":"<h3>Expertos en Modalidad 40 y Ley 73</h3>"}}
INSERT INTO public."Config_Paginas" ("id_empresa", "id_pagina", "id_cluster", "meta_json", "schema_json", "contenido_json") VALUES ('ConM40', 'aumenta tu pension', NULL, '{"title":"Requisitos para Modalidad 40 IMSS | Pensiones Ley 73","description":"¿Tienes 60 años y más de 850 semanas? Perfilamos tu caso para obtener el máximo financiamiento de tu pensión IMSS sin invertir hoy.","keywords":"requisitos modalidad 40, semanas cotizadas imss, pension 60 años, ley 73 requisitos, expediente modalidad 40","robots":"index, follow"}', '{"@context":"https://schema.org","@type":"Guide","name":"Perfilamiento de Cliente Ideal - Modalidad 40","description":"Criterios de elegibilidad para el financiamiento de pensión IMSS: Edad (59.9 años), 850+ semanas y vigencia de derechos.","author":{"@type":"Organization","name":"SUIT Expertos en Pensiones"}}', '{"hero":{"h1":"<h1>¿Tienes casi 60 años y dejaste de cotizar recientemente?</h1>","h2":"<h2>Tu mejor etapa está por comenzar: Perfilamos tu futuro</h2>","main_text":"<p>Si tienes al menos <strong>59 años y 9 meses</strong>, cuentas con más de <strong>850 semanas cotizadas</strong> y tienes un periodo sin cotizar de entre 1 y 5 años, eres el candidato perfecto.</p>","highlight_section":"<h3>Solución Integral: Expediente y Financiamiento</h3><p>Deja el papeleo en manos de expertos; armamos tu expediente y conseguimos el financiamiento que transformará tu futuro y protegerá a tu familia.</p>","cta_banner":"<h3>¡Contáctanos hoy mismo para validar tu perfil!</h3>","whatsapp_url":"https://wa.me/tu_numero?text=Hola! Cumplo con el perfil del Gancho 2: Tengo más de 850 semanas y casi 60 años para mi pensión."},"footer_seo":{"h3":"<h3>Requisitos y Elegibilidad Modalidad 40</h3>"}}') ON CONFLICT DO NOTHING;
INSERT INTO public."Config_Paginas" ("id_empresa", "id_pagina", "id_cluster", "meta_json", "schema_json", "contenido_json") VALUES ('CMARJAV', 'Story', NULL, '{"section":"story","active":true}', '{"type":"narrative"}', '{"titulo":"TU FUTURO, NUESTRA ESTRATEGIA FAMILIAR","subtitulo":"Consultoría Especializada en Retiro IMSS","p_intro":"En Pensión Inteligente, bajo la dirección de Martha y Roberto Padrón, nos dedicamos a transformar vidas. Nuestra misión es asegurar que cada trabajador de la Ley 73 obtenga la pensión máxima que por ley le corresponde, utilizando estrategias financieras transparentes y seguras.","p_mision":"Brindar tranquilidad a las familias mexicanas mediante la optimización de sus recursos de seguridad social.","imagen_url":"https://drive.google.com/uc?id=11GOSsHDaO-JmtcKd9J5Io5J8aYbcQHOH"}') ON CONFLICT DO NOTHING;
INSERT INTO public."Config_Paginas" ("id_empresa", "id_pagina", "id_cluster", "meta_json", "schema_json", "contenido_json") VALUES ('CMARJAV', 'home', NULL, '{"section":"story","active":true}', '{"type":"narrative"}', '{"titulo":"TU FUTURO, NUESTRA ESTRATEGIA FAMILIAR","subtitulo":"Consultoría Especializada en Retiro IMSS","p_intro":"En Pensión Inteligente, bajo la dirección de Martha y Roberto Padrón, nos dedicamos a transformar vidas. Nuestra misión es asegurar que cada trabajador de la Ley 73 obtenga la pensión máxima que por ley le corresponde, utilizando estrategias financieras transparentes y seguras.","p_mision":"Brindar tranquilidad a las familias mexicanas mediante la optimización de sus recursos de seguridad social.","imagen_url":"https://drive.google.com/uc?id=11GOSsHDaO-JmtcKd9J5Io5J8aYbcQHOH"}') ON CONFLICT DO NOTHING;
INSERT INTO public."Config_Paginas" ("id_empresa", "id_pagina", "id_cluster", "meta_json", "schema_json", "contenido_json") VALUES ('CMARJAV', 'requisitos', NULL, '{"section":"full-page","active":true}', '{"type":"check-list"}', '{"titulo":"REQUISITOS Y DOCUMENTACIÓN","subtitulo":"Todo comienza con una Auditoría Legal","p_intro":"Para iniciar tu proceso de mejora de pensión, requerimos integrar un expediente técnico robusto. No solicitamos dinero por adelantado.","texto":"• Identificación Oficial (INE/Pasaporte)\n• CURP y RFC actualizado\n• Estado de Cuenta AFORE (opcional)\n• Reporte de Semanas Cotizadas (lo tramitamos por ti si no lo tienes)\n• Comprobante de Domicilio","imagen_url":"https://drive.google.com/uc?id=11GOSsHDaO-JmtcKd9J5Io5J8aYbcQHOH"}') ON CONFLICT DO NOTHING;
INSERT INTO public."Config_Paginas" ("id_empresa", "id_pagina", "id_cluster", "meta_json", "schema_json", "contenido_json") VALUES ('CMARJAV', 'proceso', NULL, '{"section":"full-page","active":true}', '{"type":"workflow"}', '{"titulo":"TU CAMINO A LA PENSIÓN MÁXIMA","subtitulo":"Metodología ''Cero Desembolso''","p_intro":"Nuestra estrategia se basa en aprovechar las lagunas legales a tu favor para maximizar tu pensión sin que pongas en riesgo tu patrimonio actual.","texto":"1. Auditoría Legal IMSS (Análisis gratuito)\n2. Estrategia de Inversión Modalidad 40\n3. Financiamiento de Pago Retroactivo\n4. Trámite ante el Seguro Social\n5. Recepción de primer pago y recuperación de Afore.","imagen_url":"https://drive.google.com/uc?id=11GOSsHDaO-JmtcKd9J5Io5J8aYbcQHOH"}') ON CONFLICT DO NOTHING;
INSERT INTO public."Config_Paginas" ("id_empresa", "id_pagina", "id_cluster", "meta_json", "schema_json", "contenido_json") VALUES ('PAPER', 'home', 'LEY73', '{"section":"story","active":true}', '{"type":"narrative"}', '{"titulo":"TU PATRIMONIO, NUESTRA ESTRATEGIA FAMILIAR","subtitulo":"PA PER | Consultoría en Retiro","p_intro":"En PA PER (Padrón Pérez), bajo la dirección de Martha y Roberto Padrón, nos dedicamos a blindar tu futuro. Nuestra misión es asegurar que cada trabajador obtenga la pensión máxima, protegiendo su Patrimonio Personal.","p_mision":"Brindar seguridad patrimonial a las familias mediante la optimización de sus recursos de retiro.","imagen_url":"https://drive.google.com/uc?id=11GOSsHDaO-JmtcKd9J5Io5J8aYbcQHOH"}') ON CONFLICT DO NOTHING;
INSERT INTO public."Config_Paginas" ("id_empresa", "id_pagina", "id_cluster", "meta_json", "schema_json", "contenido_json") VALUES ('PAPER', 'requisitos', 'MOD40', '{"section":"full-page","active":true}', '{"type":"check-list"}', '{"titulo":"REQUISITOS PA PER","subtitulo":"Auditoría de Patrimonio Personal","p_intro":"Para iniciar tu proceso en PA PER, requerimos integrar un expediente técnico robusto. No solicitamos anticipos.","texto":"• Identificación Oficial\n• CURP y RFC actualizado\n• Reporte de Semanas Cotizadas\n• Comprobante de Domicilio","imagen_url":"https://drive.google.com/uc?id=11GOSsHDaO-JmtcKd9J5Io5J8aYbcQHOH"}') ON CONFLICT DO NOTHING;
INSERT INTO public."Config_Paginas" ("id_empresa", "id_pagina", "id_cluster", "meta_json", "schema_json", "contenido_json") VALUES ('PAPER', 'proceso', 'PADRON', '{"section":"full-page","active":true}', '{"type":"workflow"}', '{"titulo":"EL CAMINO PA PER","subtitulo":"Estrategia de Blindaje","p_intro":"Nuestra metodología asegura tu retiro maximizando tu pensión sin poner en riesgo tus ahorros actuales.","texto":"1. Auditoría de Patrimonio\n2. Inversión Modalidad 40\n3. Financiamiento Retroactivo\n4. Trámite IMSS\n5. Recuperación de Afore.","imagen_url":"https://drive.google.com/uc?id=11GOSsHDaO-JmtcKd9J5Io5J8aYbcQHOH"}') ON CONFLICT DO NOTHING;
INSERT INTO public."Config_Paginas" ("id_empresa", "id_pagina", "id_cluster", "meta_json", "schema_json", "contenido_json") VALUES ('SIRIS', 'estudios-energia-prefactibilidad', 'Preventa', '{"title":"Estudios de energía y prefactibilidad solar | SIRIS","description":"Estudios de energía y prefactibilidad para proyectos de paneles solares residenciales, PyME e industriales en el Noreste de México.","robots":"index,follow","keywords":"estudios de energía, prefactibilidad solar, estudio fotovoltaico, análisis energético inicial, consultoría solar Noreste de México"}', '{"@context":"https://schema.org","@type":"Service","name":"Estudios de energía y prefactibilidad solar","areaServed":"Noreste de México","provider":{"@type":"Organization","name":"SIRIS"},"serviceType":"Estudios de energía y prefactibilidad para proyectos de paneles solares.","audience":{"@type":"Audience","audienceType":["Residencial","PyME","Industrial"]}}', '{"bloques":[{"section":"story","active":true,"type":"narrative","titulo":"La decisión correcta empieza con un buen estudio","subtitulo":"Estudios de energía y prefactibilidad SIRIS","p_intro":"Antes de hablar de marcas, precios o número de paneles, en SIRIS analizamos a detalle cómo consumes energía hoy. Nuestros estudios de energía y prefactibilidad combinan tus datos de facturación con información técnica de tus instalaciones para definir si un proyecto solar realmente te conviene, qué tamaño necesita y qué retorno de inversión puedes esperar. Esto te evita inversiones impulsivas y te da argumentos sólidos para tomar decisiones frente a socios, dirección o familia.","p_mision":"Entregar a cada cliente del Noreste de México un diagnóstico claro y honesto sobre la viabilidad de su proyecto solar, alineado a sus metas financieras y operativas.","imagen_url":"https://sirisenergia.com/img/servicios/estudios-energia-prefactibilidad-story.jpg"},{"section":"full-page","active":true,"type":"check-list","titulo":"Qué incluye el estudio de prefactibilidad","subtitulo":"Más que una cotización rápida","texto":"- Revisión de recibos eléctricos y patrones de consumo mensual.\n- Identificación de horarios punta, intermedios y base.\n- Análisis preliminar de tarifas y posibles cambios regulatorios.\n- Cálculo del potencial de ahorro mediante energía solar.\n- Estimación del tamaño de sistema recomendado y superficie requerida.\n- Recomendaciones iniciales sobre esquemas de financiamiento y siguientes pasos.","imagen_url":"https://sirisenergia.com/img/servicios/estudios-energia-prefactibilidad-check.jpg"},{"section":"full-page","active":true,"type":"workflow","titulo":"Cómo realizamos tu estudio","subtitulo":"Metodología SIRIS en 3 fases","p_intro":"Mantenemos un proceso ágil: pedimos solo la información necesaria y en pocos días tienes un documento accionable para decidir.","texto":"1. Recolección de datos: recibos, información básica del inmueble y metas del proyecto.\n2. Análisis técnico–económico para estimar viabilidad e impacto en tu factura.\n3. Presentación de resultados y recomendaciones claras sobre tamaño, inversión y beneficios esperados.","imagen_url":"https://sirisenergia.com/img/servicios/estudios-energia-prefactibilidad-flujo.jpg"}]}') ON CONFLICT DO NOTHING;
INSERT INTO public."Config_Paginas" ("id_empresa", "id_pagina", "id_cluster", "meta_json", "schema_json", "contenido_json") VALUES ('SIRIS', 'analisis-consumo-dimensionamiento', 'Preventa', '{"title":"Análisis de consumo y dimensionamiento fotovoltaico | SIRIS","description":"Análisis de consumo eléctrico y dimensionamiento de sistemas fotovoltaicos para hogares, negocios y fábricas en el Noreste de México.","robots":"index,follow","keywords":"análisis de consumo eléctrico, dimensionamiento fotovoltaico, cálculo de sistema solar, tamaño de sistema solar, diseño de capacidad fotovoltaica"}', '{"@context":"https://schema.org","@type":"Service","name":"Análisis de consumo y dimensionamiento fotovoltaico","areaServed":"Noreste de México","provider":{"@type":"Organization","name":"SIRIS"},"serviceType":"Análisis de consumo eléctrico y dimensionamiento de sistemas fotovoltaicos.","audience":{"@type":"Audience","audienceType":["Residencial","PyME","Industrial"]}}', '{"bloques":[{"section":"story","active":true,"type":"narrative","titulo":"Ni de más ni de menos: el sistema justo para ti","subtitulo":"Dimensionamiento fotovoltaico SIRIS","p_intro":"Uno de los errores más comunes en proyectos solares es sobredimensionar o quedarse corto. En SIRIS usamos tu histórico de consumo, tus planes de crecimiento y las condiciones del sitio para calcular la capacidad ideal del sistema. Así evitamos que pagues por paneles que no necesitas o que te quedes con un sistema insuficiente para tus metas de ahorro.","p_mision":"Diseñar sistemas fotovoltaicos equilibrados que maximicen el retorno de inversión sin comprometer la operación eléctrica de tus instalaciones.","imagen_url":"https://sirisenergia.com/img/servicios/analisis-consumo-dimensionamiento-story.jpg"},{"section":"full-page","active":true,"type":"check-list","titulo":"Elementos que consideramos al dimensionar","subtitulo":"Más variables que solo kWh","texto":"- Consumo mensual y estacional de energía.\n- Perfil de carga por horarios y días de operación.\n- Cambios previstos: nuevas máquinas, aires, expansión de sucursales.\n- Limitaciones físicas de techos, patios y estructuras.\n- Requisitos de respaldo con baterías o plantas existentes.\n- Objetivos de compensación: porcentaje de factura que se busca cubrir con solar.","imagen_url":"https://sirisenergia.com/img/servicios/analisis-consumo-dimensionamiento-check.jpg"},{"section":"full-page","active":true,"type":"workflow","titulo":"Proceso de análisis y dimensionamiento","subtitulo":"Ingeniería basada en datos","p_intro":"Cada proyecto se modela con software especializado que replica el comportamiento de tu consumo frente a la generación solar.","texto":"1. Carga y depuración de tus datos de consumo.\n2. Simulación de distintos tamaños de sistema y análisis de resultados.\n3. Selección del escenario óptimo y presentación de un resumen ejecutivo entendible para todos los perfiles de decisión.","imagen_url":"https://sirisenergia.com/img/servicios/analisis-consumo-dimensionamiento-flujo.jpg"}]}') ON CONFLICT DO NOTHING;
INSERT INTO public."Config_Paginas" ("id_empresa", "id_pagina", "id_cluster", "meta_json", "schema_json", "contenido_json") VALUES ('SIRIS', 'evaluacion-tecnica-sitio', 'Preventa', '{"title":"Evaluación técnica de sitio para paneles solares | SIRIS","description":"Evaluación técnica de techos, estructuras, sombras y red eléctrica para proyectos de paneles solares en el Noreste de México.","robots":"index,follow","keywords":"evaluación de sitio solar, análisis de techo para paneles, estudio de sombras, revisión estructural solar, visita técnica fotovoltaica"}', '{"@context":"https://schema.org","@type":"Service","name":"Evaluación técnica de sitio para paneles solares","areaServed":"Noreste de México","provider":{"@type":"Organization","name":"SIRIS"},"serviceType":"Evaluación técnica de techos, estructuras y condiciones eléctricas para proyectos solares.","audience":{"@type":"Audience","audienceType":["Residencial","PyME","Industrial"]}}', '{"bloques":[{"section":"story","active":true,"type":"narrative","titulo":"Ver el techo antes que la cotización","subtitulo":"Evaluación técnica de sitio SIRIS","p_intro":"Un buen proyecto solar comienza con los pies en la tierra… o en el techo. En SIRIS realizamos visitas técnicas donde medimos pendientes, revisamos estructuras, detectamos sombras y validamos tu infraestructura eléctrica. Esto nos permite diseñar un sistema seguro, eficiente y compatible con tu instalación actual, reduciendo riesgos de filtraciones, sobrecargas o bajo desempeño.","p_mision":"Garantizar que cada instalación solar que diseñamos sea técnicamente viable y segura para nuestros clientes del Noreste de México.","imagen_url":"https://sirisenergia.com/img/servicios/evaluacion-tecnica-sitio-story.jpg"},{"section":"full-page","active":true,"type":"check-list","titulo":"Qué revisamos en tu inmueble","subtitulo":"Seguridad, espacio y potencial solar","texto":"- Estado físico del techo y tipo de material.\n- Resistencias estructurales y puntos de anclaje recomendados.\n- Obstáculos y sombras de árboles, edificios o equipos existentes.\n- Ubicación de centros de carga y trayectoria de cableado.\n- Posibles puntos de interconexión con la red.\n- Espacios alternos: estacionamientos, terrenos o cubiertas metálicas.","imagen_url":"https://sirisenergia.com/img/servicios/evaluacion-tecnica-sitio-check.jpg"},{"section":"full-page","active":true,"type":"workflow","titulo":"Cómo se realiza la visita técnica","subtitulo":"Inspección rápida, información valiosa","p_intro":"Buscamos afectar lo menos posible tus operaciones mientras obtenemos la información necesaria para un diseño serio.","texto":"1. Coordinación de fecha y acceso con responsables de mantenimiento o propietarios.\n2. Recorrido físico, toma de medidas, fotografías y registros eléctricos básicos.\n3. Informe técnico con recomendaciones y restricciones clave para el proyecto solar.","imagen_url":"https://sirisenergia.com/img/servicios/evaluacion-tecnica-sitio-flujo.jpg"}]}') ON CONFLICT DO NOTHING;
INSERT INTO public."Config_Paginas" ("id_empresa", "id_pagina", "id_cluster", "meta_json", "schema_json", "contenido_json") VALUES ('SIRIS', 'simulacion-produccion-retorno', 'Preventa', '{"title":"Simulación de producción solar y retorno de inversión | SIRIS","description":"Simulación de producción, ahorros y retorno de inversión para sistemas fotovoltaicos residenciales, PyME e industriales en el Noreste de México.","robots":"index,follow","keywords":"simulación de producción solar, retorno de inversión solar, ROI fotovoltaico, simulador de ahorros solares, análisis financiero solar"}', '{"@context":"https://schema.org","@type":"Service","name":"Simulación de producción solar y retorno de inversión","areaServed":"Noreste de México","provider":{"@type":"Organization","name":"SIRIS"},"serviceType":"Simulación de producción de energía y retorno de inversión para proyectos solares.","audience":{"@type":"Audience","audienceType":["Residencial","PyME","Industrial"]}}', '{"bloques":[{"section":"story","active":true,"type":"narrative","titulo":"Del kilowatt al peso: hacemos números contigo","subtitulo":"Simulación de producción y ROI SIRIS","p_intro":"Invertir en paneles solares es una decisión financiera, no solo tecnológica. En SIRIS modelamos cómo se comportará tu sistema a lo largo de los años, considerando radiación local, degradación de paneles, tarifas eléctricas y posibles incrementos de consumo. Traducimos la producción esperada en pesos ahorrados, periodo de recuperación e impacto en tu flujo de efectivo, para que veas con claridad si el proyecto cumple tus metas.","p_mision":"Ofrecer a cada cliente un análisis financiero transparente que muestre claramente el impacto económico de su proyecto solar antes de invertir un solo peso.","imagen_url":"https://sirisenergia.com/img/servicios/simulacion-produccion-retorno-story.jpg"},{"section":"full-page","active":true,"type":"check-list","titulo":"Qué entregamos en la simulación","subtitulo":"Escenarios claros para decidir","texto":"- Proyección anual de generación de energía por al menos 20 años.\n- Estimación de ahorros en la factura eléctrica por escenario.\n- Cálculo del periodo de recuperación de la inversión (payback).\n- Cálculo de TIR y valor presente neto cuando aplica.\n- Escenarios conservador, medio y optimista de desempeño.\n- Resumen ejecutivo listo para presentar a socios, dirección o inversionistas.","imagen_url":"https://sirisenergia.com/img/servicios/simulacion-produccion-retorno-check.jpg"},{"section":"full-page","active":true,"type":"workflow","titulo":"Metodología de simulación SIRIS","subtitulo":"Datos locales, criterios realistas","p_intro":"Usamos datos de radiación del Noreste de México y supuestos conservadores de degradación y pérdidas para no prometer ahorros irreales.","texto":"1. Integración del diseño preliminar del sistema con ubicación, orientación y potencia.\n2. Simulación de producción con software especializado y aplicación de factores de pérdida.\n3. Conversión de energía generada en ahorros económicos y métricas financieras clave, que se presentan en un informe fácil de entender y compartir.","imagen_url":"https://sirisenergia.com/img/servicios/simulacion-produccion-retorno-flujo.jpg"}]}') ON CONFLICT DO NOTHING;
INSERT INTO public."Config_Paginas" ("id_empresa", "id_pagina", "id_cluster", "meta_json", "schema_json", "contenido_json") VALUES ('SIRIS', 'asesoria-regulatoria-incentivos', 'Preventa', '{"title":"Asesoría regulatoria, tarifas e incentivos solares | SIRIS","description":"Asesoría sobre regulación eléctrica, tarifas e incentivos para proyectos de paneles solares residenciales, PyME e industriales en el Noreste de México.","robots":"index,follow","keywords":"asesoría regulatoria solar, tarifas eléctricas, incentivos solares, interconexión fotovoltaica, trámites para paneles solares, regulación eléctrica México"}', '{"@context":"https://schema.org","@type":"Service","name":"Asesoría regulatoria, tarifas e incentivos solares","areaServed":"Noreste de México","provider":{"@type":"Organization","name":"SIRIS"},"serviceType":"Asesoría en regulación eléctrica, tarifas e incentivos aplicables a proyectos solares.","audience":{"@type":"Audience","audienceType":["Residencial","PyME","Industrial"]}}', '{"bloques":[{"section":"story","active":true,"type":"narrative","titulo":"Menos trámites, más claridad para tu proyecto solar","subtitulo":"Asesoría regulatoria e incentivos SIRIS","p_intro":"El valor de un sistema fotovoltaico no depende solo de los equipos, sino también de cómo se integra al marco regulatorio. En SIRIS te ayudamos a entender qué reglas aplican a tu proyecto según tu tarifa, nivel de tensión y tipo de cliente. Explicamos en lenguaje claro los pasos para interconectarte, los requisitos básicos y las oportunidades de incentivos o beneficios fiscales disponibles, para que avances con certeza jurídica y financiera.","p_mision":"Reducir la fricción regulatoria de los proyectos solares en el Noreste de México, guiando a nuestros clientes en cada decisión clave relacionada con tarifas e incentivos.","imagen_url":"https://sirisenergia.com/img/servicios/asesoria-regulatoria-incentivos-story.jpg"},{"section":"full-page","active":true,"type":"check-list","titulo":"Qué cubre nuestra asesoría regulatoria","subtitulo":"Del esquema de interconexión a los beneficios fiscales","texto":"- Análisis de tu tarifa actual y riesgos de cambio de esquema.\n- Explicación de opciones de interconexión para generación distribuida y media escala.\n- Revisión de requisitos básicos de contratos y permisos.\n- Identificación de incentivos o beneficios fiscales aplicables a tu proyecto.\n- Orientación sobre documentación y tiempos estimados de respuesta.\n- Acompañamiento de alto nivel durante gestiones con la compañía eléctrica y asesores fiscales.","imagen_url":"https://sirisenergia.com/img/servicios/asesoria-regulatoria-incentivos-check.jpg"},{"section":"full-page","active":true,"type":"workflow","titulo":"Cómo te guiamos en la parte regulatoria","subtitulo":"De la duda al plan de acción","p_intro":"Nuestro objetivo es que tengas un mapa claro de qué hacer, en qué orden y qué puedes esperar en cada etapa del trámite.","texto":"1. Entendemos tu contexto: tipo de cliente, tarifa y objetivos del proyecto solar.\n2. Definimos contigo el esquema de interconexión y los beneficios potenciales.\n3. Trazamos un plan de trámites, documentación y responsables, que te permita avanzar de forma ordenada y sin sobresaltos.","imagen_url":"https://sirisenergia.com/img/servicios/asesoria-regulatoria-incentivos-flujo.jpg"}]}') ON CONFLICT DO NOTHING;
INSERT INTO public."Config_Paginas" ("id_empresa", "id_pagina", "id_cluster", "meta_json", "schema_json", "contenido_json") VALUES ('SIRIS', 'ingenieria-detalle-solar', 'Ingeniería', '{"title":"Ingeniería de detalle eléctrica y estructural para sistemas solares | SIRIS","description":"Ingeniería de detalle eléctrica y estructural para proyectos de paneles solares residenciales, PyME e industriales en el Noreste de México.","robots":"index,follow","keywords":"ingeniería de detalle solar, diseño eléctrico fotovoltaico, cálculo estructural para paneles, planos de instalación solar, ingeniería de sistemas fotovoltaicos"}', '{"@context":"https://schema.org","@type":"Service","name":"Ingeniería de detalle eléctrica y estructural para sistemas solares","areaServed":"Noreste de México","provider":{"@type":"Organization","name":"SIRIS"},"serviceType":"Ingeniería de detalle eléctrica y estructural para sistemas fotovoltaicos en techos, estacionamientos y suelo.","audience":{"@type":"Audience","audienceType":["Residencial","PyME","Industrial"]}}', '{"bloques":[{"section":"story","active":true,"type":"narrative","titulo":"Ingeniería que convierte ideas solares en planos ejecutables","subtitulo":"Ingeniería de detalle SIRIS","p_intro":"Un buen estudio y una buena simulación necesitan traducirse en planos claros para instaladores y autoridades. En SIRIS desarrollamos la ingeniería de detalle eléctrica y estructural de tu sistema solar, cuidando desde calibres de cable y protecciones hasta cargas sobre techos, pendientes y anclajes. Nuestro enfoque es asegurar que el proyecto sea seguro, normativo y fácilmente construible, reduciendo improvisaciones y costos extra en obra.","p_mision":"Entregar proyectos solares con ingeniería sólida, lista para instalarse de forma segura y eficiente en hogares, negocios y plantas industriales del Noreste de México.","imagen_url":"https://sirisenergia.com/img/servicios/ingenieria-detalle-solar-story.jpg"},{"section":"full-page","active":true,"type":"check-list","titulo":"Qué incluye la ingeniería de detalle","subtitulo":"Planos y memorias listos para obra","texto":"- Diagramas unifilares y de interconexión eléctrica.\n- Especificación de inversores, protecciones y calibres de conductores.\n- Planos de distribución de paneles en techo, estacionamiento o suelo.\n- Criterios de cálculo estructural y selección de sistemas de montaje.\n- Memorias técnicas y listas de materiales (BOM) para ejecución.\n- Recomendaciones de canalizaciones, rutas de cable y puntos de conexión.","imagen_url":"https://sirisenergia.com/img/servicios/ingenieria-detalle-solar-check.jpg"},{"section":"full-page","active":true,"type":"workflow","titulo":"Cómo desarrollamos la ingeniería de tu proyecto","subtitulo":"Del concepto al plano constructivo","p_intro":"Trabajamos de la mano con tu área técnica, mantenimiento o despacho de arquitectura para que la solución se integre bien al inmueble.","texto":"1. Recepción de información base: levantamiento, estudios previos y objetivos de diseño.\n2. Desarrollo de planos eléctricos y estructurales con criterios normativos.\n3. Revisión conjunta y ajustes finales, hasta llegar a un juego de planos listo para instalación y trámites.","imagen_url":"https://sirisenergia.com/img/servicios/ingenieria-detalle-solar-flujo.jpg"}]}') ON CONFLICT DO NOTHING;
INSERT INTO public."Config_Paginas" ("id_empresa", "id_pagina", "id_cluster", "meta_json", "schema_json", "contenido_json") VALUES ('SIRIS', 'diseno-sistemas-solares-residenciales', 'Ingeniería', '{"title":"Diseño de sistemas solares residenciales | SIRIS","description":"Diseño de sistemas fotovoltaicos residenciales a la medida para casas y departamentos en el Noreste de México.","robots":"index,follow","keywords":"diseño de sistemas solares residenciales, paneles solares para casa, sistema fotovoltaico hogar, proyecto solar residencial, energía solar Noreste de México"}', '{"@context":"https://schema.org","@type":"Service","name":"Diseño de sistemas solares residenciales","areaServed":"Noreste de México","provider":{"@type":"Organization","name":"SIRIS"},"serviceType":"Diseño de sistemas fotovoltaicos residenciales a la medida para casas y departamentos.","audience":{"@type":"Audience","audienceType":["Residencial"]}}', '{"bloques":[{"section":"story","active":true,"type":"narrative","titulo":"Un sistema solar pensado para tu casa, no genérico","subtitulo":"Diseño residencial SIRIS","p_intro":"Cada hogar tiene un estilo de vida, hábitos de consumo y espacios distintos. En SIRIS diseñamos sistemas solares residenciales personalizados, considerando cuántas personas viven en la casa, el uso de clima, electrodomésticos y posibles ampliaciones futuras. Buscamos que tu sistema sea estético, seguro y financieramente atractivo, integrándose al diseño de tu vivienda sin afectar su imagen ni su funcionalidad diaria.","p_mision":"Ayudar a las familias del Noreste de México a reducir su recibo de luz con sistemas solares residenciales a la medida, que se vean bien y funcionen mejor.","imagen_url":"https://sirisenergia.com/img/servicios/diseno-sistemas-solares-residenciales-story.jpg"},{"section":"full-page","active":true,"type":"check-list","titulo":"Cómo es un diseño residencial SIRIS","subtitulo":"Cuidado en lo técnico y en lo estético","texto":"- Análisis de consumo específico de la vivienda y horarios de uso.\n- Definición del porcentaje de la factura que se desea cubrir con solar.\n- Selección de ubicaciones óptimas: techo, cochera o estructuras ligeras.\n- Propuesta de configuración de paneles, inversor y protecciones.\n- Cálculo de producción esperada y ahorros anuales.\n- Recomendaciones de monitoreo y posibles integraciones con domótica.","imagen_url":"https://sirisenergia.com/img/servicios/diseno-sistemas-solares-residenciales-check.jpg"},{"section":"full-page","active":true,"type":"workflow","titulo":"Proceso de diseño para tu casa","subtitulo":"De tu recibo de luz al plano de instalación","p_intro":"Mantendremos la comunicación simple y transparente para que tú y tu familia entiendan el proyecto desde el inicio.","texto":"1. Revisión de recibos y breve entrevista sobre hábitos de consumo y planes futuros.\n2. Evaluación de espacios disponibles y restricciones de la vivienda.\n3. Propuesta de diseño con esquema de instalación, producción esperada y opciones de inversión, lista para avanzar a la siguiente etapa del proyecto.","imagen_url":"https://sirisenergia.com/img/servicios/diseno-sistemas-solares-residenciales-flujo.jpg"}]}') ON CONFLICT DO NOTHING;
INSERT INTO public."Config_Paginas" ("id_empresa", "id_pagina", "id_cluster", "meta_json", "schema_json", "contenido_json") VALUES ('SIRIS', 'diseno-sistemas-solares-pyme', 'Ingeniería', '{"title":"Diseño de sistemas solares para PyME y comercios | SIRIS","description":"Diseño de sistemas fotovoltaicos para PyME, comercios y oficinas en el Noreste de México, enfocados en ahorro y control de costos energéticos.","robots":"index,follow","keywords":"diseño de sistemas solares para PyME, paneles solares para negocios, sistema fotovoltaico comercial, proyecto solar para comercios, energía solar para oficinas"}', '{"@context":"https://schema.org","@type":"Service","name":"Diseño de sistemas solares para PyME y comercios","areaServed":"Noreste de México","provider":{"@type":"Organization","name":"SIRIS"},"serviceType":"Diseño de sistemas fotovoltaicos para PyME, comercios y oficinas.","audience":{"@type":"Audience","audienceType":["PyME"]}}', '{"bloques":[{"section":"story","active":true,"type":"narrative","titulo":"Tu negocio necesita costos de energía predecibles","subtitulo":"Diseño solar para PyME y comercios SIRIS","p_intro":"Para una PyME o comercio, el recibo de luz impacta directamente en la utilidad del negocio. En SIRIS diseñamos sistemas solares que se ajustan a tus horarios de operación, equipos críticos y planes de crecimiento. Evaluamos cómo afectan la energía y la climatización a tu estructura de costos y proponemos soluciones que te den más control sobre el gasto eléctrico, sin frenar tu operación diaria ni a tus clientes.","p_mision":"Apoyar a negocios y oficinas del Noreste de México a proteger su rentabilidad mediante diseños solares que equilibran ahorro, inversión y continuidad operativa.","imagen_url":"https://sirisenergia.com/img/servicios/diseno-sistemas-solares-pyme-story.jpg"},{"section":"full-page","active":true,"type":"check-list","titulo":"Elementos clave en un diseño para PyME","subtitulo":"Pensado para flujo de efectivo y operación","texto":"- Análisis de consumos por horario y temporada según el giro del negocio.\n- Identificación de cargas críticas: refrigeración, aire acondicionado, equipos de proceso.\n- Revisión de espacios disponibles: techos, estacionamientos o estructuras ligeras.\n- Propuesta de configuración de paneles, inversores y protecciones con enfoque comercial.\n- Estimación de producción y ahorros, ligada al flujo de efectivo del negocio.\n- Posibles escenarios de integración con financiamiento o contratos tipo PPA.","imagen_url":"https://sirisenergia.com/img/servicios/diseno-sistemas-solares-pyme-check.jpg"},{"section":"full-page","active":true,"type":"workflow","titulo":"Cómo diseñamos tu sistema para negocio","subtitulo":"De tus números al proyecto solar","p_intro":"Buscamos que la inversión en solar se entienda como un proyecto financiero más dentro de tu empresa, con metas claras y supuestos bien documentados.","texto":"1. Revisión de historial de consumo y entendimiento del modelo de negocio.\n2. Evaluación técnica de espacios y condiciones eléctricas en la sucursal u oficina.\n3. Presentación de un diseño solar con escenarios de ahorro e inversión, alineado a tu estrategia de crecimiento y al nivel de riesgo que estás dispuesto a asumir.","imagen_url":"https://sirisenergia.com/img/servicios/diseno-sistemas-solares-pyme-flujo.jpg"}]}') ON CONFLICT DO NOTHING;
INSERT INTO public."Config_Paginas" ("id_empresa", "id_pagina", "id_cluster", "meta_json", "schema_json", "contenido_json") VALUES ('SIRIS', 'diseno-sistemas-solares-industriales', 'Ingeniería', '{"title":"Diseño de sistemas solares industriales y en suelo | SIRIS","description":"Diseño de sistemas fotovoltaicos industriales y en suelo para plantas, parques industriales y grandes consumidores en el Noreste de México.","robots":"index,follow","keywords":"diseño de sistemas solares industriales, parques solares en suelo, fotovoltaico para industria, proyectos solares de gran escala, energía solar para plantas industriales"}', '{"@context":"https://schema.org","@type":"Service","name":"Diseño de sistemas solares industriales y en suelo","areaServed":"Noreste de México","provider":{"@type":"Organization","name":"SIRIS"},"serviceType":"Diseño de sistemas fotovoltaicos industriales en techo y en suelo para grandes consumidores de energía.","audience":{"@type":"Audience","audienceType":["Industrial"]}}', '{"bloques":[{"section":"story","active":true,"type":"narrative","titulo":"Proyectos solares industriales pensados para producción continua","subtitulo":"Diseño industrial y en suelo SIRIS","p_intro":"Las plantas industriales y parques logísticos requieren soluciones solares robustas, escalables y alineadas a su operación 24/7. En SIRIS diseñamos sistemas fotovoltaicos para naves, patios y terrenos disponibles dentro o cerca del sitio industrial, cuidando la coordinación con procesos productivos, seguridad industrial y mantenimientos programados. Nuestro enfoque combina criterios eléctricos, mecánicos y operativos para que la energía solar se vuelva un aliado estratégico y no un riesgo para la continuidad de tu planta.","p_mision":"Diseñar soluciones solares industriales y en suelo que reduzcan costos energéticos de grandes consumidores sin comprometer la confiabilidad de sus operaciones.","imagen_url":"https://sirisenergia.com/img/servicios/diseno-sistemas-solares-industriales-story.jpg"},{"section":"full-page","active":true,"type":"check-list","titulo":"Qué consideramos en un diseño industrial","subtitulo":"Más allá del techo disponible","texto":"- Análisis detallado del perfil de carga de la planta y procesos críticos.\n- Evaluación de techos, estacionamientos y terrenos para instalación en suelo.\n- Definición de esquemas de interconexión y coordinación con infraestructura existente.\n- Segmentación de bloques de generación por áreas o centros de carga.\n- Criterios de redundancia, seguridad eléctrica y compatibilidad con protecciones.\n- Escenarios de expansión futura del sistema solar conforme crece la planta.","imagen_url":"https://sirisenergia.com/img/servicios/diseno-sistemas-solares-industriales-check.jpg"},{"section":"full-page","active":true,"type":"workflow","titulo":"Proceso de diseño para industria y grandes sitios","subtitulo":"Diagnóstico profundo, proyecto escalable","p_intro":"Sabemos que cada decisión técnica impacta en producción, por eso integramos a tus equipos de mantenimiento, ingeniería y seguridad desde el inicio.","texto":"1. Levantamiento avanzado: visitas técnicas, planos, unifilares y requerimientos de operación.\n2. Modelado de opciones de instalación en techo, estacionamiento y suelo con escenarios de capacidad.\n3. Presentación del diseño recomendado con fases de implementación, estimados de ahorro y compatibilidad con tus planes de crecimiento energético e industrial.","imagen_url":"https://sirisenergia.com/img/servicios/diseno-sistemas-solares-industriales-flujo.jpg"}]}') ON CONFLICT DO NOTHING;
INSERT INTO public."Config_Paginas" ("id_empresa", "id_pagina", "id_cluster", "meta_json", "schema_json", "contenido_json") VALUES ('SIRIS', 'procura-logistica-equipos-solares', 'Ingeniería', '{"title":"Procura y logística de equipos solares | SIRIS","description":"Procura y logística de paneles, inversores, estructuras y accesorios solares para proyectos residenciales, PyME e industriales en el Noreste de México.","robots":"index,follow","keywords":"procura de equipos solares, logística de paneles solares, suministro fotovoltaico, paneles e inversores Noreste de México, gestión de inventarios solares"}', '{"@context":"https://schema.org","@type":"Service","name":"Procura y logística de equipos solares","areaServed":"Noreste de México","provider":{"@type":"Organization","name":"SIRIS"},"serviceType":"Procura, suministro y logística de equipos para sistemas fotovoltaicos.","audience":{"@type":"Audience","audienceType":["Residencial","PyME","Industrial"]}}', '{"bloques":[{"section":"story","active":true,"type":"narrative","titulo":"Los equipos correctos, en el lugar correcto y en el momento correcto","subtitulo":"Procura y logística SIRIS","p_intro":"Un buen diseño solar puede fallar si los equipos no llegan a tiempo o no cumplen las especificaciones. En SIRIS gestionamos la procura integral de paneles, inversores, estructuras, cables y protecciones, trabajando con marcas probadas y cadenas de suministro confiables. Coordinamos tiempos de entrega por etapas, validamos lotes y cuidamos que cada componente llegue completo y en buen estado al sitio de instalación, evitando retrasos y sobrecostos en obra.","p_mision":"Asegurar que cada proyecto solar en el Noreste de México cuente con los equipos adecuados, certificados y entregados a tiempo para una instalación eficiente.","imagen_url":"https://sirisenergia.com/img/servicios/procura-logistica-equipos-solares-story.jpg"},{"section":"full-page","active":true,"type":"check-list","titulo":"Qué incluye nuestro servicio de procura","subtitulo":"Del pedido al sitio de instalación","texto":"- Selección de proveedores y marcas alineadas al diseño de ingeniería.\n- Cotización y compra de paneles, inversores, estructuras y accesorios.\n- Planeación de entregas parciales o completas según el programa de obra.\n- Coordinación de transporte, maniobras y almacenamiento temporal.\n- Verificación de cantidades, modelos y estado físico de los equipos.\n- Documentación de garantías y manuales para cada componente.","imagen_url":"https://sirisenergia.com/img/servicios/procura-logistica-equipos-solares-check.jpg"},{"section":"full-page","active":true,"type":"workflow","titulo":"Cómo operamos la cadena de suministro solar","subtitulo":"Comunicación constante con ingeniería y obra","p_intro":"Nuestro equipo de procura trabaja en contacto permanente con ingeniería y el responsable de campo para ajustar volúmenes y tiempos cuando el proyecto lo requiere.","texto":"1. Recepción de listas de materiales (BOM) y planos de ingeniería.\n2. Selección de proveedores, negociación y colocación de órdenes de compra.\n3. Coordinación de entregas y validación de equipos en sitio, con reportes claros para el cliente y el equipo de instalación.","imagen_url":"https://sirisenergia.com/img/servicios/procura-logistica-equipos-solares-flujo.jpg"}]}') ON CONFLICT DO NOTHING;
INSERT INTO public."Config_Paginas" ("id_empresa", "id_pagina", "id_cluster", "meta_json", "schema_json", "contenido_json") VALUES ('SIRIS', 'instalacion-llave-en-mano-sistemas-solares', 'Ingeniería', '{"title":"Instalación llave en mano de sistemas solares | SIRIS","description":"Instalación llave en mano de sistemas fotovoltaicos residenciales, PyME e industriales en el Noreste de México, con equipos certificados y cuadrillas especializadas.","robots":"index,follow","keywords":"instalación de paneles solares, sistemas solares llave en mano, instalación fotovoltaica residencial, instalación solar comercial, cuadrillas de instalación solar, proyectos solares Noreste de México"}', '{"@context":"https://schema.org","@type":"Service","name":"Instalación llave en mano de sistemas solares","areaServed":"Noreste de México","provider":{"@type":"Organization","name":"SIRIS"},"serviceType":"Instalación llave en mano de sistemas fotovoltaicos residenciales, comerciales e industriales.","audience":{"@type":"Audience","audienceType":["Residencial","PyME","Industrial"]}}', '{"bloques":[{"section":"story","active":true,"type":"narrative","titulo":"De los planos a la realidad: instalamos tu sistema solar de principio a fin","subtitulo":"Instalación llave en mano SIRIS","p_intro":"Con SIRIS no tienes que coordinar proveedores por separado. Nuestro servicio de instalación llave en mano se encarga de todo: estructuras, paneles, cableado, protecciones y puesta en servicio preliminar. Trabajamos con cuadrillas capacitadas y protocolos de seguridad para intervenir en techos, estacionamientos o suelo sin afectar tu operación diaria. El resultado es un sistema instalado de forma ordenada, limpia y conforme a lo definido en la ingeniería de detalle.","p_mision":"Entregar instalaciones solares de alta calidad que funcionen desde el primer día y sienten las bases para una operación confiable a largo plazo en el Noreste de México.","imagen_url":"https://sirisenergia.com/img/servicios/instalacion-llave-en-mano-sistemas-solares-story.jpg"},{"section":"full-page","active":true,"type":"check-list","titulo":"Qué incluye una instalación llave en mano","subtitulo":"Todo lo necesario para dejar el sistema montado","texto":"- Montaje de estructuras y anclajes en techo, estacionamiento o suelo.\n- Colocación y conexionado de paneles fotovoltaicos.\n- Instalación de inversores, tableros y protecciones eléctricas.\n- Tendido y sujeción de cableado en rutas seguras y ordenadas.\n- Etiquetado, señalización básica y orden en el área intervenida.\n- Pruebas iniciales de funcionamiento y revisión de parámetros clave.","imagen_url":"https://sirisenergia.com/img/servicios/instalacion-llave-en-mano-sistemas-solares-check.jpg"},{"section":"full-page","active":true,"type":"workflow","titulo":"Cómo ejecutamos la instalación de tu sistema","subtitulo":"Planeación, seguridad y supervisión","p_intro":"Nuestro proceso busca minimizar tiempos muertos y riesgos, cumpliendo los estándares definidos en ingeniería y seguridad industrial.","texto":"1. Planeación de obra: calendario de actividades, accesos y zonas de trabajo.\n2. Instalación física de estructuras, paneles y equipos eléctricos con supervisión técnica.\n3. Pruebas de continuidad, aislamiento y verificación general, dejando el sistema listo para la etapa formal de puesta en marcha e interconexión.","imagen_url":"https://sirisenergia.com/img/servicios/instalacion-llave-en-mano-sistemas-solares-flujo.jpg"}]}') ON CONFLICT DO NOTHING;
INSERT INTO public."Config_Paginas" ("id_empresa", "id_pagina", "id_cluster", "meta_json", "schema_json", "contenido_json") VALUES ('SIRIS', 'integracion-baterias-microredes', 'Ingeniería', '{"title":"Integración de baterías y microredes solares | SIRIS","description":"Integración de baterías de litio y microredes solares para respaldo, ahorro y estabilidad energética en proyectos residenciales, PyME e industriales en el Noreste de México.","robots":"index,follow","keywords":"integración de baterías solares, microredes fotovoltaicas, respaldo con baterías de litio, sistemas híbridos solar-red, almacenamiento de energía Noreste de México"}', '{"@context":"https://schema.org","@type":"Service","name":"Integración de baterías y microredes solares","areaServed":"Noreste de México","provider":{"@type":"Organization","name":"SIRIS"},"serviceType":"Diseño e integración de baterías y microredes solares para respaldo y optimización energética.","audience":{"@type":"Audience","audienceType":["Residencial","PyME","Industrial"]}}', '{"bloques":[{"section":"story","active":true,"type":"narrative","titulo":"Energía solar incluso cuando la red se va","subtitulo":"Integración de baterías y microredes SIRIS","p_intro":"Cuando la continuidad de servicio es crítica, un sistema solar convencional puede no ser suficiente. En SIRIS diseñamos e integramos soluciones con baterías de litio y microredes solares que permiten seguir operando en apagones, reducir picos de demanda y aprovechar mejor cada kWh generado. Combinamos generación fotovoltaica, almacenamiento y la red eléctrica para darte mayor independencia y control sobre tu suministro de energía.","p_mision":"Proporcionar a hogares, negocios e industrias del Noreste de México soluciones solares híbridas y de respaldo que aumenten su resiliencia energética y su capacidad de ahorro.","imagen_url":"https://sirisenergia.com/img/servicios/integracion-baterias-microredes-story.jpg"},{"section":"full-page","active":true,"type":"check-list","titulo":"Qué podemos hacer con baterías y microredes","subtitulo":"Respaldo, ahorro y estabilidad","texto":"- Diseño de sistemas solares con baterías para respaldo de cargas críticas.\n- Configuración de sistemas híbridos solar–red–batería.\n- Estrategias para reducción de picos de demanda y optimización de tarifas.\n- Integración con plantas de emergencia existentes.\n- Definición de tiempos de autonomía y prioridades de carga.\n- Monitoreo y gestión inteligente del estado de carga y uso de las baterías.","imagen_url":"https://sirisenergia.com/img/servicios/integracion-baterias-microredes-check.jpg"},{"section":"full-page","active":true,"type":"workflow","titulo":"Cómo integramos baterías y microredes","subtitulo":"Diseño coordinado con tu operación","p_intro":"Analizamos qué tan sensible es tu operación a los cortes de energía y cómo se comporta tu demanda para definir la solución adecuada, sin sobredimensionar.","texto":"1. Identificación de cargas críticas y análisis de eventos de falla en tu sitio.\n2. Definición de la estrategia de respaldo y ahorro (respaldo total, parcial o solo picos).\n3. Diseño e integración del sistema de baterías y microred solar, con configuración, pruebas y capacitación básica para tu equipo.","imagen_url":"https://sirisenergia.com/img/servicios/integracion-baterias-microredes-flujo.jpg"}]}') ON CONFLICT DO NOTHING;
INSERT INTO public."Config_Paginas" ("id_empresa", "id_pagina", "id_cluster", "meta_json", "schema_json", "contenido_json") VALUES ('SIRIS', 'integracion-cargadores-vehiculos-electricos', 'Ingeniería', '{"title":"Integración de cargadores para vehículos eléctricos y sistemas solares | SIRIS","description":"Integración de cargadores para vehículos eléctricos con sistemas fotovoltaicos en hogares, negocios y flotas en el Noreste de México.","robots":"index,follow","keywords":"cargadores para vehículos eléctricos, integración solar y EV, estaciones de carga con paneles solares, carga de autos eléctricos en casa, carga de flotas comerciales eléctrica"}', '{"@context":"https://schema.org","@type":"Service","name":"Integración de cargadores para vehículos eléctricos y sistemas solares","areaServed":"Noreste de México","provider":{"@type":"Organization","name":"SIRIS"},"serviceType":"Diseño e integración de cargadores para vehículos eléctricos con sistemas fotovoltaicos residenciales, comerciales e industriales.","audience":{"@type":"Audience","audienceType":["Residencial","PyME","Industrial"]}}', '{"bloques":[{"section":"story","active":true,"type":"narrative","titulo":"Tu energía solar también puede mover tus vehículos","subtitulo":"Integración solar + vehículos eléctricos SIRIS","p_intro":"La transición a vehículos eléctricos es más poderosa cuando se combina con energía solar. En SIRIS diseñamos e integramos estaciones de carga para autos eléctricos que aprovechan tu sistema fotovoltaico existente o uno nuevo. Evaluamos horarios de carga, número de vehículos y capacidad disponible para que puedas recargar con energía limpia sin comprometer el funcionamiento normal de tu hogar, negocio o planta.","p_mision":"Ayudar a familias, empresas y flotas del Noreste de México a electrificar su movilidad con soluciones de carga bien integradas a sus sistemas solares.","imagen_url":"https://sirisenergia.com/img/servicios/integracion-cargadores-vehiculos-electricos-story.jpg"},{"section":"full-page","active":true,"type":"check-list","titulo":"Qué incluye la integración de cargadores EV","subtitulo":"De la idea al punto de carga operativo","texto":"- Análisis de tu sistema solar y capacidad disponible para carga de vehículos.\n- Selección de cargadores residenciales, comerciales o para flotas según el caso.\n- Diseño de la infraestructura eléctrica necesaria para las estaciones de carga.\n- Integración con el sistema fotovoltaico y con la red eléctrica.\n- Opciones de medición, control de acceso y registro de consumos.\n- Recomendaciones sobre ubicación, señalización y crecimiento futuro del punto de carga.","imagen_url":"https://sirisenergia.com/img/servicios/integracion-cargadores-vehiculos-electricos-check.jpg"},{"section":"full-page","active":true,"type":"workflow","titulo":"Cómo desarrollamos tu proyecto de carga eléctrica","subtitulo":"Integración segura y escalable","p_intro":"Buscamos que tu primera estación de carga sea el inicio de una estrategia de movilidad eléctrica, no un punto aislado y difícil de operar.","texto":"1. Revisión de tu consumo actual y del sistema solar instalado o proyectado.\n2. Definición del número de cargadores, niveles de carga y casos de uso (hogar, clientes, empleados, flota).\n3. Implementación de la infraestructura de carga integrada a tu sistema, con pruebas, configuración básica y guía para su uso diario.","imagen_url":"https://sirisenergia.com/img/servicios/integracion-cargadores-vehiculos-electricos-flujo.jpg"}]}') ON CONFLICT DO NOTHING;
INSERT INTO public."Config_Paginas" ("id_empresa", "id_pagina", "id_cluster", "meta_json", "schema_json", "contenido_json") VALUES ('SIRIS', 'puesta-en-marcha-entrega-sistemas-fotovoltaicos', 'Ingeniería', '{"title":"Puesta en marcha y entrega de sistemas fotovoltaicos | SIRIS","description":"Puesta en marcha, pruebas y entrega formal de sistemas fotovoltaicos residenciales, PyME e industriales en el Noreste de México.","robots":"index,follow","keywords":"puesta en marcha de sistemas solares, pruebas de sistemas fotovoltaicos, entrega de proyecto solar, comisionamiento de paneles solares, verificación de sistema fotovoltaico"}', '{"@context":"https://schema.org","@type":"Service","name":"Puesta en marcha y entrega de sistemas fotovoltaicos","areaServed":"Noreste de México","provider":{"@type":"Organization","name":"SIRIS"},"serviceType":"Puesta en marcha, pruebas y entrega formal de sistemas fotovoltaicos instalados.","audience":{"@type":"Audience","audienceType":["Residencial","PyME","Industrial"]}}', '{"bloques":[{"section":"story","active":true,"type":"narrative","titulo":"No solo instalamos: comprobamos que tu sistema funcione como debe","subtitulo":"Puesta en marcha y entrega SIRIS","p_intro":"El cierre de un proyecto solar no es cuando se atornilla el último panel, sino cuando el sistema opera dentro de los parámetros esperados. En SIRIS realizamos la puesta en marcha de tus sistemas fotovoltaicos con pruebas eléctricas, verificación de protecciones y validación del monitoreo. Al finalizar, te entregamos un informe de comisionamiento y un recorrido guiado por el sistema para que sepas cómo está configurado y qué indicadores debes vigilar.","p_mision":"Asegurar que cada sistema solar instalado en el Noreste de México inicie operación de forma segura, estable y documentada, listo para generar ahorros desde el primer día.","imagen_url":"https://sirisenergia.com/img/servicios/puesta-en-marcha-entrega-sistemas-fotovoltaicos-story.jpg"},{"section":"full-page","active":true,"type":"check-list","titulo":"Qué hacemos en la puesta en marcha","subtitulo":"Verificación completa antes de entregarte el sistema","texto":"- Revisión visual y mecánica de estructuras, paneles y fijaciones.\n- Pruebas eléctricas básicas: continuidad, polaridad y aislamiento.\n- Configuración inicial de inversores, protecciones y parámetros de operación.\n- Validación del sistema de monitoreo y registro de datos.\n- Verificación de producción inicial contra lo esperado para las condiciones del día.\n- Elaboración de acta de entrega y reporte de comisionamiento.","imagen_url":"https://sirisenergia.com/img/servicios/puesta-en-marcha-entrega-sistemas-fotovoltaicos-check.jpg"},{"section":"full-page","active":true,"type":"workflow","titulo":"Cómo es el proceso de entrega SIRIS","subtitulo":"Del montaje a la operación estable","p_intro":"Nuestro objetivo es que recibas un sistema listo para operar, con documentación y una explicación clara de su funcionamiento.","texto":"1. Ejecución de pruebas y ajustes finales en campo para estabilizar la operación.\n2. Configuración y validación de monitoreo, accesos y parámetros visibles para el cliente.\n3. Reunión de entrega donde revisamos el sistema contigo, explicamos puntos clave y acordamos el plan de operación y mantenimiento a seguir.","imagen_url":"https://sirisenergia.com/img/servicios/puesta-en-marcha-entrega-sistemas-fotovoltaicos-flujo.jpg"}]}') ON CONFLICT DO NOTHING;
INSERT INTO public."Config_Paginas" ("id_empresa", "id_pagina", "id_cluster", "meta_json", "schema_json", "contenido_json") VALUES ('SIRIS', 'monitoreo-remoto-sistemas-fotovoltaicos', 'Mantenimiento', '{"title":"Monitoreo remoto 24/7 de sistemas fotovoltaicos | SIRIS","description":"Monitoreo remoto 24/7 de sistemas fotovoltaicos residenciales, PyME e industriales en el Noreste de México, con alertas de desempeño y reportes periódicos.","robots":"index,follow","keywords":"monitoreo remoto de sistemas solares, supervisión 24/7 fotovoltaica, plataforma de monitoreo solar, alertas de bajo desempeño, reportes de energía solar"}', '{"@context":"https://schema.org","@type":"Service","name":"Monitoreo remoto 24/7 de sistemas fotovoltaicos","areaServed":"Noreste de México","provider":{"@type":"Organization","name":"SIRIS"},"serviceType":"Monitoreo remoto de sistemas solares con alertas y reportes de desempeño.","audience":{"@type":"Audience","audienceType":["Residencial","PyME","Industrial"]}}', '{"bloques":[{"section":"story","active":true,"type":"narrative","titulo":"Tu sistema solar siempre bajo vigilancia, aunque tú no lo veas","subtitulo":"Monitoreo remoto SIRIS","p_intro":"Un sistema solar sin monitoreo es como un coche sin tablero. En SIRIS conectamos tus inversores y sensores a plataformas de monitoreo remoto que nos permiten vigilar la producción de energía, detectar caídas de desempeño y anticipar posibles fallas. Así, tú puedes enfocarte en tu casa o negocio mientras nosotros cuidamos que tu inversión fotovoltaica esté generando lo que debe.","p_mision":"Mantener vigilados los sistemas solares de nuestros clientes del Noreste de México para maximizar su producción y reducir tiempos muertos por fallas no detectadas.","imagen_url":"https://sirisenergia.com/img/servicios/monitoreo-remoto-sistemas-fotovoltaicos-story.jpg"},{"section":"full-page","active":true,"type":"check-list","titulo":"Qué incluye el monitoreo remoto SIRIS","subtitulo":"Visibilidad y alertas sobre tu energía","texto":"- Conexión de tu sistema a una plataforma de monitoreo en la nube.\n- Visualización de producción diaria, mensual y acumulada.\n- Detección de anomalías y alertas por bajo desempeño.\n- Comparación contra curvas de generación esperada.\n- Accesos para que tú también puedas revisar tu sistema desde web o app.\n- Reportes periódicos con hallazgos y recomendaciones de mejora.","imagen_url":"https://sirisenergia.com/img/servicios/monitoreo-remoto-sistemas-fotovoltaicos-check.jpg"},{"section":"full-page","active":true,"type":"workflow","titulo":"Cómo operamos el servicio de monitoreo","subtitulo":"Datos que se convierten en acciones","p_intro":"No solo almacenamos datos; los interpretamos para tomar decisiones de mantenimiento y avisarte cuando algo requiere atención.","texto":"1. Alta de tu sistema en la plataforma y definición de umbrales de alerta.\n2. Revisión continua de indicadores clave de producción y estado de equipos.\n3. Emisión de reportes y generación de tickets de mantenimiento cuando se detecta una desviación importante en el desempeño.","imagen_url":"https://sirisenergia.com/img/servicios/monitoreo-remoto-sistemas-fotovoltaicos-flujo.jpg"}]}') ON CONFLICT DO NOTHING;
INSERT INTO public."Config_Paginas" ("id_empresa", "id_pagina", "id_cluster", "meta_json", "schema_json", "contenido_json") VALUES ('SIRIS', 'mantenimiento-preventivo-limpieza-paneles', 'Mantenimiento', '{"title":"Mantenimiento preventivo y limpieza de paneles solares | SIRIS","description":"Mantenimiento preventivo y limpieza profesional de paneles solares para sistemas residenciales, PyME e industriales en el Noreste de México.","robots":"index,follow","keywords":"mantenimiento preventivo de paneles solares, limpieza de paneles solares, servicio de mantenimiento fotovoltaico, cuidado de sistemas solares, mantenimiento solar residencial comercial industrial"}', '{"@context":"https://schema.org","@type":"Service","name":"Mantenimiento preventivo y limpieza de paneles solares","areaServed":"Noreste de México","provider":{"@type":"Organization","name":"SIRIS"},"serviceType":"Mantenimiento preventivo y limpieza de paneles solares y componentes asociados.","audience":{"@type":"Audience","audienceType":["Residencial","PyME","Industrial"]}}', '{"bloques":[{"section":"story","active":true,"type":"narrative","titulo":"Un sistema solar limpio y cuidado produce más","subtitulo":"Mantenimiento preventivo SIRIS","p_intro":"El polvo, la suciedad y las pequeñas fallas invisibles reducen poco a poco la producción de tu sistema solar. En SIRIS ofrecemos planes de mantenimiento preventivo que incluyen limpieza profesional de paneles y revisión periódica de estructuras, conexiones y protecciones. Nuestro objetivo es preservar el desempeño del sistema, alargar la vida útil de los equipos y evitar paros inesperados que afecten tus ahorros o tu operación.","p_mision":"Mantener en óptimas condiciones los sistemas fotovoltaicos del Noreste de México mediante mantenimientos preventivos programados y seguros.","imagen_url":"https://sirisenergia.com/img/servicios/mantenimiento-preventivo-limpieza-paneles-story.jpg"},{"section":"full-page","active":true,"type":"check-list","titulo":"Qué incluye el mantenimiento preventivo","subtitulo":"Cuidado integral más allá de la limpieza","texto":"- Limpieza de paneles solares con métodos adecuados al tipo de superficie.\n- Inspección visual de estructuras, fijaciones y sellos.\n- Revisión de conexiones eléctricas y aprietes en tableros.\n- Comprobación básica de protecciones y dispositivos de seguridad.\n- Revisión de lecturas en inversores y comparación con valores esperados.\n- Reporte de hallazgos y recomendaciones de acciones correctivas si se requieren.","imagen_url":"https://sirisenergia.com/img/servicios/mantenimiento-preventivo-limpieza-paneles-check.jpg"},{"section":"full-page","active":true,"type":"workflow","titulo":"Cómo operan nuestros planes de mantenimiento","subtitulo":"Visitas programadas y trazabilidad","p_intro":"Adaptamos la frecuencia de mantenimiento al tamaño de tu sistema, las condiciones ambientales y la criticidad de tu operación.","texto":"1. Definición del plan anual de visitas según tipo de cliente y entorno.\n2. Ejecución de mantenimiento preventivo con registro fotográfico y mediciones clave.\n3. Entrega de reporte y actualización de historial de mantenimiento para tomar decisiones futuras sobre tu sistema.","imagen_url":"https://sirisenergia.com/img/servicios/mantenimiento-preventivo-limpieza-paneles-flujo.jpg"}]}') ON CONFLICT DO NOTHING;
INSERT INTO public."Config_Paginas" ("id_empresa", "id_pagina", "id_cluster", "meta_json", "schema_json", "contenido_json") VALUES ('SIRIS', 'mantenimiento-correctivo-atencion-fallas', 'Mantenimiento', '{"title":"Mantenimiento correctivo y atención a fallas en sistemas solares | SIRIS","description":"Mantenimiento correctivo y atención a fallas en sistemas fotovoltaicos residenciales, PyME e industriales en el Noreste de México.","robots":"index,follow","keywords":"mantenimiento correctivo de sistemas solares, reparación de paneles solares, fallas en inversores fotovoltaicos, servicio técnico solar, atención de averías solares"}', '{"@context":"https://schema.org","@type":"Service","name":"Mantenimiento correctivo y atención a fallas en sistemas solares","areaServed":"Noreste de México","provider":{"@type":"Organization","name":"SIRIS"},"serviceType":"Diagnóstico y corrección de fallas en sistemas fotovoltaicos, incluyendo inversores, paneles y cableado.","audience":{"@type":"Audience","audienceType":["Residencial","PyME","Industrial"]}}', '{"bloques":[{"section":"story","active":true,"type":"narrative","titulo":"Cuando tu sistema solar falla, respondemos rápido","subtitulo":"Mantenimiento correctivo SIRIS","p_intro":"Aunque un sistema solar bien diseñado es muy confiable, pueden presentarse fallas por clima, uso, equipo o instalaciones previas. En SIRIS ofrecemos servicio de mantenimiento correctivo para diagnosticar y resolver problemas en sistemas fotovoltaicos nuevos o existentes, aunque no los hayamos instalado nosotros. Nuestro enfoque es recuperar la operación lo antes posible, priorizando la seguridad y documentando el origen de la falla para evitar que se repita.","p_mision":"Brindar a los usuarios de energía solar en el Noreste de México una respuesta técnica rápida y profesional ante cualquier falla en sus sistemas fotovoltaicos.","imagen_url":"https://sirisenergia.com/img/servicios/mantenimiento-correctivo-atencion-fallas-story.jpg"},{"section":"full-page","active":true,"type":"check-list","titulo":"Tipos de fallas que atendemos","subtitulo":"Desde alarmas hasta paros totales","texto":"- Inversores que marcan alarmas o dejan de producir.\n- Strings o grupos de paneles que no generan energía.\n- Disparos frecuentes de protecciones o breakers.\n- Daños físicos por viento, granizo o golpes accidentales.\n- Problemas de calentamiento anormal en conexiones o tableros.\n- Fallas recurrentes en sistemas instalados por terceros que requieren diagnóstico profundo.","imagen_url":"https://sirisenergia.com/img/servicios/mantenimiento-correctivo-atencion-fallas-check.jpg"},{"section":"full-page","active":true,"type":"workflow","titulo":"Cómo atendemos una falla en tu sistema","subtitulo":"Diagnóstico claro antes de intervenir","p_intro":"Buscamos que entiendas qué pasó, qué se corrige y qué acciones preventivas se recomiendan para el futuro.","texto":"1. Levantamiento inicial de información: síntomas, fotos, historial y datos de equipos.\n2. Visita técnica para mediciones, pruebas y localización de la causa raíz.\n3. Propuesta y ejecución de la corrección necesaria, con reporte final y recomendaciones para mejorar la confiabilidad del sistema.","imagen_url":"https://sirisenergia.com/img/servicios/mantenimiento-correctivo-atencion-fallas-flujo.jpg"}]}') ON CONFLICT DO NOTHING;
INSERT INTO public."Config_Paginas" ("id_empresa", "id_pagina", "id_cluster", "meta_json", "schema_json", "contenido_json") VALUES ('SIRIS', 'gestion-garantias-documentacion-solar', 'Mantenimiento', '{"title":"Gestión de garantías y documentación técnica de sistemas solares | SIRIS","description":"Gestión de garantías, manuales y documentación técnica de sistemas fotovoltaicos residenciales, PyME e industriales en el Noreste de México.","robots":"index,follow","keywords":"gestión de garantías de paneles solares, documentación técnica fotovoltaica, manuales de sistemas solares, apoyo en garantías de inversores, control de expedientes de proyectos solares"}', '{"@context":"https://schema.org","@type":"Service","name":"Gestión de garantías y documentación técnica de sistemas solares","areaServed":"Noreste de México","provider":{"@type":"Organization","name":"SIRIS"},"serviceType":"Gestión de garantías con fabricantes y administración de documentación técnica de sistemas fotovoltaicos.","audience":{"@type":"Audience","audienceType":["Residencial","PyME","Industrial"]}}', '{"bloques":[{"section":"story","active":true,"type":"narrative","titulo":"Tus garantías y documentos solares, en orden y a la mano","subtitulo":"Gestión de garantías y documentación SIRIS","p_intro":"Un sistema solar bien instalado debe ir acompañado de un expediente técnico completo. En SIRIS organizamos y resguardamos la documentación de tu proyecto: facturas, certificados, manuales, fichas técnicas y pólizas de garantía. Cuando se presenta una falla cubierta por fabricante, te ayudamos a documentarla y dar seguimiento con la marca para agilizar el reemplazo o reparación, evitando que pierdas beneficios por falta de información o tiempos.","p_mision":"Proteger la inversión de nuestros clientes del Noreste de México manteniendo ordenada y accesible toda la documentación y garantías de sus sistemas solares.","imagen_url":"https://sirisenergia.com/img/servicios/gestion-garantias-documentacion-solar-story.jpg"},{"section":"full-page","active":true,"type":"check-list","titulo":"Qué incluye nuestra gestión de garantías","subtitulo":"Respaldo documental para todo tu sistema","texto":"- Integración del expediente técnico del proyecto solar.\n- Archivo de contratos, facturas, fichas técnicas y manuales.\n- Registro de vigencias y alcances de las garantías de cada equipo.\n- Apoyo en la documentación de fallas para aplicar garantías.\n- Canalización y seguimiento de casos con fabricantes y distribuidores.\n- Entrega de respaldos digitales para fácil consulta por parte del cliente.","imagen_url":"https://sirisenergia.com/img/servicios/gestion-garantias-documentacion-solar-check.jpg"},{"section":"full-page","active":true,"type":"workflow","titulo":"Cómo administramos tu documentación técnica","subtitulo":"Del cierre de obra al ciclo de vida del sistema","p_intro":"Nuestro objetivo es que, ante cualquier eventualidad, tengas a la mano la información necesaria para responder rápido y con confianza.","texto":"1. Recolección y clasificación de todos los documentos generados durante el proyecto.\n2. Creación de un expediente físico y digital con estructura clara por tipo de equipo.\n3. Actualización del expediente cuando hay reemplazos, ampliaciones o cambios, manteniendo vigente la información para futuras reclamaciones o auditorías.","imagen_url":"https://sirisenergia.com/img/servicios/gestion-garantias-documentacion-solar-flujo.jpg"}]}') ON CONFLICT DO NOTHING;
INSERT INTO public."Config_Paginas" ("id_empresa", "id_pagina", "id_cluster", "meta_json", "schema_json", "contenido_json") VALUES ('SIRIS', 'repowering-actualizacion-sistemas-solares', 'Mantenimiento', '{"title":"Repowering y actualización de sistemas solares existentes | SIRIS","description":"Repowering y actualización de sistemas fotovoltaicos residenciales, PyME e industriales en el Noreste de México para mejorar producción y confiabilidad.","robots":"index,follow","keywords":"repowering de sistemas solares, actualización de paneles solares, cambio de inversores fotovoltaicos, mejora de producción solar, modernización de sistemas solares existentes"}', '{"@context":"https://schema.org","@type":"Service","name":"Repowering y actualización de sistemas solares existentes","areaServed":"Noreste de México","provider":{"@type":"Organization","name":"SIRIS"},"serviceType":"Repowering y actualización de componentes en sistemas fotovoltaicos ya instalados.","audience":{"@type":"Audience","audienceType":["Residencial","PyME","Industrial"]}}', '{"bloques":[{"section":"story","active":true,"type":"narrative","titulo":"Dale una segunda vida a tu sistema solar","subtitulo":"Repowering y actualización SIRIS","p_intro":"Muchos sistemas solares instalados hace años producen menos de lo que podrían o presentan fallas recurrentes por tecnología antigua o malas prácticas de instalación. En SIRIS analizamos el estado de tu sistema existente y proponemos un plan de repowering: cambio de inversores, reconfiguración de strings, incorporación de nuevos paneles o mejoras en protecciones. El objetivo es recuperar y, en muchos casos, aumentar la producción de energía extendiendo la vida útil de la inversión original.","p_mision":"Ayudar a los usuarios de sistemas solares en el Noreste de México a modernizar y optimizar sus instalaciones existentes, maximizando su desempeño y seguridad.","imagen_url":"https://sirisenergia.com/img/servicios/repowering-actualizacion-sistemas-solares-story.jpg"},{"section":"full-page","active":true,"type":"check-list","titulo":"Qué podemos mejorar en tu sistema actual","subtitulo":"Diagnóstico y acciones de repowering","texto":"- Evaluación del estado y desempeño de paneles e inversores.\n- Revisión de configuraciones eléctricas y protecciones instaladas.\n- Propuestas de reemplazo de inversores por modelos más eficientes.\n- Reconfiguración de strings y arreglos para mejorar producción.\n- Incorporación de nuevos módulos o ampliaciones del sistema.\n- Corrección de detalles de instalación que afecten seguridad o rendimiento.","imagen_url":"https://sirisenergia.com/img/servicios/repowering-actualizacion-sistemas-solares-check.jpg"},{"section":"full-page","active":true,"type":"workflow","titulo":"Cómo trabajamos un proyecto de repowering","subtitulo":"Del diagnóstico a la mejora medible","p_intro":"Buscamos que puedas comparar el antes y el después de tu sistema, tanto en energía producida como en estabilidad de operación.","texto":"1. Diagnóstico técnico del sistema existente con mediciones y revisión de historial.\n2. Propuesta de acciones de repowering priorizadas por impacto y presupuesto.\n3. Ejecución de las mejoras acordadas y seguimiento de la producción para validar el incremento logrado.","imagen_url":"https://sirisenergia.com/img/servicios/repowering-actualizacion-sistemas-solares-flujo.jpg"}]}') ON CONFLICT DO NOTHING;
INSERT INTO public."Config_Paginas" ("id_empresa", "id_pagina", "id_cluster", "meta_json", "schema_json", "contenido_json") VALUES ('SIRIS', 'creditos-proyectos-paneles-solares', 'Financiamiento', '{"title":"Créditos para proyectos de paneles solares | SIRIS","description":"Créditos para financiar proyectos de paneles solares residenciales, PyME e industriales en el Noreste de México, con pagos alineados a tus ahorros de energía.","robots":"index,follow","keywords":"créditos para paneles solares, financiamiento solar, crédito fotovoltaico residencial, crédito solar para negocios, préstamo para sistemas solares Noreste de México"}', '{"@context":"https://schema.org","@type":"Service","name":"Créditos para proyectos de paneles solares","areaServed":"Noreste de México","provider":{"@type":"Organization","name":"SIRIS"},"serviceType":"Créditos para financiar la compra e instalación de sistemas fotovoltaicos.","audience":{"@type":"Audience","audienceType":["Residencial","PyME","Industrial"]}}', '{"bloques":[{"section":"story","active":true,"type":"narrative","titulo":"Convierte tu recibo de luz en la mensualidad de tu sistema solar","subtitulo":"Créditos para proyectos solares SIRIS","p_intro":"Muchas familias y empresas quieren instalar paneles solares, pero les preocupa el desembolso inicial. En SIRIS te ayudamos a estructurar créditos para proyectos fotovoltaicos donde la mensualidad se acerque a lo que hoy pagas de recibo de luz. De esta forma, transformas un gasto operativo en una inversión de largo plazo, con la ventaja de que, una vez liquidado el crédito, sigues disfrutando de ahorros por muchos años.","p_mision":"Facilitar el acceso a energía solar en el Noreste de México mediante esquemas de crédito claros, sostenibles y alineados a la realidad financiera de cada cliente.","imagen_url":"https://sirisenergia.com/img/servicios/creditos-proyectos-paneles-solares-story.jpg"},{"section":"full-page","active":true,"type":"check-list","titulo":"Cómo te apoyamos con créditos solares","subtitulo":"Financiamiento que entiende tu flujo de efectivo","texto":"- Análisis de tu capacidad de pago con base en historial de consumo y finanzas básicas.\n- Estimación de un rango de crédito adecuado al tamaño del proyecto.\n- Estructuración de plazos y montos mensuales alineados a tus ahorros esperados.\n- Coordinación con instituciones financieras aliadas cuando aplica.\n- Integración de la información técnica del proyecto para la evaluación del crédito.\n- Acompañamiento en el proceso hasta la autorización y disposición de recursos.","imagen_url":"https://sirisenergia.com/img/servicios/creditos-proyectos-paneles-solares-check.jpg"},{"section":"full-page","active":true,"type":"workflow","titulo":"Proceso para obtener un crédito con enfoque solar","subtitulo":"De tu recibo de luz a la aprobación","p_intro":"Buscamos que el proceso sea tan simple como contratar un servicio, pero con el rigor financiero necesario para protegerte a ti y a tu proyecto.","texto":"1. Revisión del estudio energético y del monto estimado de inversión.\n2. Análisis básico de perfil financiero y selección del tipo de crédito adecuado.\n3. Integración del expediente y gestión con la entidad financiera hasta la autorización, coordinando tiempos con el arranque del proyecto de instalación solar.","imagen_url":"https://sirisenergia.com/img/servicios/creditos-proyectos-paneles-solares-flujo.jpg"}]}') ON CONFLICT DO NOTHING;
INSERT INTO public."Config_Paginas" ("id_empresa", "id_pagina", "id_cluster", "meta_json", "schema_json", "contenido_json") VALUES ('SIRIS', 'leasing-arrendamiento-sistemas-fotovoltaicos', 'Financiamiento', '{"title":"Leasing y arrendamiento de sistemas fotovoltaicos | SIRIS","description":"Leasing y arrendamiento de sistemas fotovoltaicos para clientes residenciales, PyME e industriales en el Noreste de México, con pagos fijos y opción a compra.","robots":"index,follow","keywords":"leasing de paneles solares, arrendamiento de sistemas fotovoltaicos, renta de equipos solares, leasing solar para empresas, arrendamiento solar residencial"}', '{"@context":"https://schema.org","@type":"Service","name":"Leasing y arrendamiento de sistemas fotovoltaicos","areaServed":"Noreste de México","provider":{"@type":"Organization","name":"SIRIS"},"serviceType":"Esquemas de leasing y arrendamiento de sistemas fotovoltaicos con pagos periódicos y opción a compra.","audience":{"@type":"Audience","audienceType":["Residencial","PyME","Industrial"]}}', '{"bloques":[{"section":"story","active":true,"type":"narrative","titulo":"Disfruta los beneficios del solar sin comprar todo el activo desde el día uno","subtitulo":"Leasing y arrendamiento solar SIRIS","p_intro":"Para muchos clientes, tener un sistema solar propio no es la única opción. El leasing y el arrendamiento permiten usar equipos fotovoltaicos a cambio de pagos periódicos, manteniendo liquidez y flexibilidad contable. En SIRIS estructuramos esquemas donde tú utilizas el sistema, aprovechas el ahorro en tu recibo y, según el modelo, puedes ejercer una opción de compra al final del plazo. Así conviertes un gasto recurrente en un activo cuando tu empresa o familia está lista.","p_mision":"Ofrecer alternativas de arrendamiento solar que faciliten la adopción de energía limpia en el Noreste de México sin comprometer el capital de nuestros clientes.","imagen_url":"https://sirisenergia.com/img/servicios/leasing-arrendamiento-sistemas-fotovoltaicos-story.jpg"},{"section":"full-page","active":true,"type":"check-list","titulo":"Ventajas del leasing y arrendamiento solar","subtitulo":"Flexibilidad financiera y operativa","texto":"- Pagos periódicos predecibles en lugar de un desembolso inicial alto.\n- Posible tratamiento contable como gasto operativo según el esquema.\n- Inclusión de mantenimiento en algunos modelos de arrendamiento.\n- Opción de compra al final del plazo en esquemas de leasing.\n- Facilidad para actualizar tecnología al renovar contrato.\n- Alineación de pagos con los ahorros estimados en el recibo de luz.","imagen_url":"https://sirisenergia.com/img/servicios/leasing-arrendamiento-sistemas-fotovoltaicos-check.jpg"},{"section":"full-page","active":true,"type":"workflow","titulo":"Cómo estructuramos tu arrendamiento solar","subtitulo":"Un modelo adaptado a tu realidad","p_intro":"No todos los clientes necesitan el mismo tipo de contrato; por eso revisamos tu situación financiera, fiscal y operativa antes de recomendar un esquema.","texto":"1. Análisis del proyecto solar y de tus objetivos financieros y contables.\n2. Definición del plazo, monto de renta y responsabilidades de cada parte.\n3. Formalización del contrato de arrendamiento o leasing y coordinación con la instalación del sistema, para que empieces a ahorrar desde los primeros meses de operación.","imagen_url":"https://sirisenergia.com/img/servicios/leasing-arrendamiento-sistemas-fotovoltaicos-flujo.jpg"}]}') ON CONFLICT DO NOTHING;
INSERT INTO public."Config_Paginas" ("id_empresa", "id_pagina", "id_cluster", "meta_json", "schema_json", "contenido_json") VALUES ('SIRIS', 'contratos-ppa-pago-por-kwh', 'Financiamiento', '{"title":"Contratos PPA y modelos de pago por kWh solar | SIRIS","description":"Contratos PPA y modelos de pago por kWh para proyectos solares en el Noreste de México, ideales para empresas y grandes consumidores que prefieren pagar solo por la energía generada.","robots":"index,follow","keywords":"contratos PPA solares, pago por kWh solar, compra de energía fotovoltaica, PPA para empresas, modelo sin inversión inicial solar"}', '{"@context":"https://schema.org","@type":"Service","name":"Contratos PPA y modelos de pago por kWh solar","areaServed":"Noreste de México","provider":{"@type":"Organization","name":"SIRIS"},"serviceType":"Contratos de compra de energía (PPA) y modelos de pago por kWh generado con sistemas solares.","audience":{"@type":"Audience","audienceType":["PyME","Industrial"]}}', '{"bloques":[{"section":"story","active":true,"type":"narrative","titulo":"Energía solar sin comprar el sistema, pagando solo por kWh","subtitulo":"Contratos PPA y pago por kWh SIRIS","p_intro":"Para muchas empresas, invertir en activos no es la mejor estrategia, pero sí lo es asegurar energía más barata y limpia a largo plazo. Con los contratos PPA y modelos de pago por kWh de SIRIS, un tercero financia, instala y opera el sistema solar en tu sitio, y tú solo pagas por la energía generada, a una tarifa acordada y generalmente menor a la de la red. Esto te permite capturar ahorros desde el primer mes sin inmovilizar capital ni asumir toda la responsabilidad técnica del sistema.","p_mision":"Ofrecer a empresas y grandes consumidores del Noreste de México esquemas de compra de energía solar que reduzcan su costo eléctrico sin necesidad de invertir en infraestructura propia.","imagen_url":"https://sirisenergia.com/img/servicios/contratos-ppa-pago-por-kwh-story.jpg"},{"section":"full-page","active":true,"type":"check-list","titulo":"Beneficios de un PPA o pago por kWh","subtitulo":"Energía como servicio, no como activo","texto":"- Cero o mínima inversión inicial en infraestructura solar.\n- Pago solo por la energía efectivamente generada por el sistema.\n- Tarifas competitivas y predecibles a largo plazo.\n- Transferencia de la mayoría de riesgos técnicos y de desempeño al proveedor.\n- Opciones de compra del sistema al final del contrato en algunos modelos.\n- Mejora de tu perfil ambiental y de sostenibilidad sin modificar tu balance de activos.","imagen_url":"https://sirisenergia.com/img/servicios/contratos-ppa-pago-por-kwh-check.jpg"},{"section":"full-page","active":true,"type":"workflow","titulo":"Cómo estructuramos un modelo PPA","subtitulo":"De tu consumo actual al contrato de energía","p_intro":"Cada contrato se diseña considerando tu curva de carga, horizonte de planeación y apetito de riesgo, para asegurar que el acuerdo tenga sentido para ambas partes.","texto":"1. Análisis de tu consumo, perfil de carga y espacio disponible para instalar el sistema.\n2. Definición de la capacidad solar, plazo del contrato y tarifa por kWh a ofrecer.\n3. Firma del contrato PPA, instalación del sistema y arranque de la facturación mensual de energía generada, con reportes claros de producción y ahorros frente a la red.","imagen_url":"https://sirisenergia.com/img/servicios/contratos-ppa-pago-por-kwh-flujo.jpg"}]}') ON CONFLICT DO NOTHING;
INSERT INTO public."Config_Paginas" ("id_empresa", "id_pagina", "id_cluster", "meta_json", "schema_json", "contenido_json") VALUES ('SIRIS', 'Valor agregado e integracion solar', 'Domótica', '{"title":"Integración de solar con domótica y energía inteligente | SIRIS","description":"Integración de paneles solares con sistemas de domótica y gestión inteligente de energía para hogares, PyME e industria en el Noreste de México.","robots":"index,follow","keywords":"integración solar y domótica, energía inteligente, control de cargas con paneles solares, automatización energética, gestión inteligente de consumo eléctrico"}', '{"@context":"https://schema.org","@type":"Service","name":"Integración de solar con domótica y energía inteligente","areaServed":"Noreste de México","provider":{"@type":"Organization","name":"SIRIS"},"serviceType":"Integración de sistemas fotovoltaicos con domótica y soluciones de gestión inteligente de energía.","audience":{"@type":"Audience","audienceType":["Residencial","PyME","Industrial"]}}', '{"bloques":[{"section":"story","active":true,"type":"narrative","titulo":"Convierte tu sistema solar en un cerebro energético para tu inmueble","subtitulo":"Energía inteligente y domótica SIRIS","p_intro":"Generar energía limpia es solo el primer paso. En SIRIS te ayudamos a aprovechar mejor cada kWh integrando tus paneles solares con soluciones de domótica y gestión inteligente. Desde automatizar encendidos y apagados hasta priorizar cargas críticas cuando hay menos generación, diseñamos escenarios que alinean tu consumo con la producción solar, reducen desperdicios y hacen tu operación más cómoda y predecible.","p_mision":"Impulsar en el Noreste de México inmuebles residenciales, comerciales e industriales más eficientes y confortables, donde la energía solar y la automatización trabajen juntas.","imagen_url":"https://sirisenergia.com/img/servicios/integracion-solar-domotica-energia-inteligente-story.jpg"},{"section":"full-page","active":true,"type":"check-list","titulo":"Qué podemos automatizar con energía solar","subtitulo":"Más control, menos derroche","texto":"- Integración del sistema solar con plataformas de domótica existentes o nuevas.\n- Programación horaria de iluminación, clima y equipos no críticos.\n- Priorización de cargas esenciales cuando hay menor generación o uso de baterías.\n- Escenarios automáticos según ocupación, horarios y condiciones climáticas.\n- Monitoreo centralizado de consumos por área o tipo de carga.\n- Alertas por consumos anormales que ayuden a detectar fugas o malos usos.","imagen_url":"https://sirisenergia.com/img/servicios/integracion-solar-domotica-energia-inteligente-check.jpg"},{"section":"full-page","active":true,"type":"workflow","titulo":"Cómo diseñamos tu ecosistema de energía inteligente","subtitulo":"Diagnóstico, integración y ajuste fino","p_intro":"No se trata de llenar tu inmueble de gadgets, sino de usar la tecnología correcta donde realmente aporta valor y ahorro.","texto":"1. Diagnóstico de tus patrones de consumo y de los sistemas existentes de control o climatización.\n2. Definición de una estrategia de automatización alineada a la producción solar y a tus prioridades de operación o confort.\n3. Implementación de dispositivos, programación de escenas y ajustes finos, con monitoreo inicial para validar que los cambios se traduzcan en ahorro y mejor experiencia de uso.","imagen_url":"https://sirisenergia.com/img/servicios/integracion-solar-domotica-energia-inteligente-flujo.jpg"}]}') ON CONFLICT DO NOTHING;
INSERT INTO public."Config_Paginas" ("id_empresa", "id_pagina", "id_cluster", "meta_json", "schema_json", "contenido_json") VALUES ('SIRIS', 'Instalacion regional', 'Instalacion regional', '{"title":"Gestión de Portafolios Solares para Empresas y Corporativos | SIRIS","description":"Optimiza la energía de tus sucursales con nuestra gestión solar multirregional. Estandarización de ingeniería, monitoreo consolidado y soporte a nivel nacional.","keywords":"energía solar corporativa, gestión portafolio solar, soluciones fotovoltaicas multirregionales, ahorro energético empresas méxico","og_image":"https://sirisenergia.com/img/servicios/gestion-multirregional-portafolios-solares-story.jpg"}', '{"@context":"https://schema.org","@type":"Service","name":"Gestión de Portafolios Solares Multirregionales","description":"Ingeniería y administración centralizada de sistemas fotovoltaicos para empresas con múltiples sedes y centros de distribución.","provider":{"@type":"Organization","name":"SIRIS Energia Solar","url":"https://sirisenergia.com"},"areaServed":{"@type":"Country","name":"Mexico"},"serviceType":"Solar Energy Asset Management"}', '{"bloques":[{"section":"story","active":true,"type":"narrative","titulo":"Gestión de Portafolios Solares para Empresas de Múltiples Sedes","subtitulo":"Un modelo energético unificado para toda tu organización","p_intro":"Cuando tu empresa opera decenas de sucursales o centros de distribución, la energía limpia se vuelve una estrategia de eficiencia global. En SIRIS diseñamos soluciones fotovoltaicas multirregionales bajo estándares de ingeniería de alto nivel. Así aseguras que cada nueva instalación se integre de forma consistente y que el desempeño logre medirse bajo los mismos indicadores de rendimiento. <a href=''#contact'' style=''color:var(--primary-color); font-weight:bold;''>Solicita un diagnóstico de portafolio hoy.</a>","p_mision":"Ayudamos a corporativos e industrias del Noreste de México a construir activos solares ordenados, rentables y fáciles de escalar a nivel nacional.","imagen_url":"https://sirisenergia.com/img/servicios/gestion-multirregional-portafolios-solares-story.jpg","alt_img":"Panel de control y gestión de portafolio solar corporativo SIRIS"},{"section":"full-page","active":true,"type":"check-list","titulo":"Alcance de la Gestión Multirregional","subtitulo":"Gobernanza y control centralizado de activos energéticos","texto":"- Definición de estándares técnicos unificados para todas las sedes.\n- Coordinación logística con equipos especializados en cada ciudad.\n- Auditoría de garantías y centralización de manuales de mantenimiento.\n- Monitoreo de producción fotovoltaica consolidado por región.\n- Detección de oportunidades para ampliación de sistemas (repowering).\n- Soporte estratégico directo a departamentos de finanzas y activos.","imagen_url":"https://sirisenergia.com/img/servicios/gestion-multirregional-portafolios-solares-check.jpg","alt_img":"Ingeniero revisando checklist técnico de instalación solar multirregional"},{"section":"full-page","active":true,"type":"workflow","titulo":"Metodología de Implementación Multisitio","subtitulo":"Estrategia centralizada con ejecución local eficiente","p_intro":"Nuestro modelo permite que Dirección tenga visibilidad global, mientras que cada gerencia local cuenta con acompañamiento técnico durante la fase de operación.","texto":"1. Auditoría del inventario energético y solar de tus sedes actuales.\n2. Diseño del Plan Maestro de despliegue y estandarización de proyectos solares.\n3. Ejecución por fases con monitoreo remoto centralizado y reportes de ahorros.","imagen_url":"https://sirisenergia.com/img/servicios/gestion-multirregional-portafolios-solares-flujo.jpg","alt_img":"Flujograma de trabajo SIRIS para proyectos solares corporativos"}]}') ON CONFLICT DO NOTHING;
